const LESSONS = {
  beginner:[
    { id:"b1", title:"Pre-Trip Inspection", icon:"🔍", duration:"3 min read", xp:50, content:[
      { type:"intro", text:"A pre-trip inspection is required by FMCSA before every trip. Missing defects can lead to accidents, fines, or failed roadside inspections. This is your first line of safety and your legal responsibility." },
      { type:"steps", title:"7-Step Inspection Process", items:[
        "1. Approach and Overview - Walk around the truck noting obvious damage, leaks, or tire issues.",
        "2. Engine Compartment - Check oil, coolant, power steering fluid, belts, hoses.",
        "3. Cab Interior - Gauges, mirrors, seatbelt, horn, wipers, emergency equipment.",
        "4. Lights and Reflectors - Test all headlights, brake lights, turn signals, marker lights.",
        "5. Front Axle and Steering - Tires, lug nuts, steering linkage, brake components.",
        "6. Fuel and Exhaust - No leaks, secure caps, exhaust routing intact, no smoke.",
        "7. Cargo and Coupling - Verify load secured, fifth wheel locked, glad hands connected.",
      ]},
      { type:"tip", text:"Do your inspection in the same order every single time. Muscle memory is what saves you at 5am in a dark truck stop. I have seen drivers skip steps and lose their CDL over preventable violations." },
      { type:"quiz", q:"How often is a pre-trip inspection legally required?", opts:["Once a week","Before every trip","Every 500 miles","Only for loads over 10,000 lbs"], ans:1, exp:"FMCSA 49 CFR Section 392.7 requires a vehicle inspection before every trip. There are no exceptions for short hauls or familiar routes." },
    ]},
    { id:"b2", title:"Backing Maneuvers", icon:"🔄", duration:"3 min read", xp:75, content:[
      { type:"intro", text:"Backing causes more accidents than any other trucking maneuver. G.O.A.L. - Get Out And Look - is not optional. Professional drivers do it every time, no matter how experienced they are." },
      { type:"steps", title:"The Four Core Backing Types", items:[
        "Straight-line backing - Equal mirror use, small corrections early, never chase the trailer.",
        "Offset backing - Set the trailer angle first, then align the tractor. Never rush the set.",
        "45-degree alley dock - Approach angle determines success. Perfect your setup, not your recovery.",
        "Parallel parking - Requires 3 reference points. Know your truck dimensions cold.",
      ]},
      { type:"tip", text:"S.M.S.M. Small moves, small moves. One inch of wheel equals feet of trailer at the rear. Get out and look every time you lose sight of a reference point. Pride has cost more drivers their jobs than any other mistake." },
      { type:"quiz", q:"What does G.O.A.L. stand for?", opts:["Get Out And Look","Go On A Lane","Guide Other Auto Lanes","Grip On A Load"], ans:0, exp:"G.O.A.L. means Get Out And Look. Always physically walk behind your truck and check clearances before and during any backing maneuver." },
    ]},
    { id:"b3", title:"Road Driving Fundamentals", icon:"🛣️", duration:"3 min read", xp:60, content:[
      { type:"intro", text:"A fully loaded semi truck at 80,000 lbs needs 4-6 times the stopping distance of a car. Everything about driving a CMV requires earlier decisions, more space, and smoother inputs." },
      { type:"steps", title:"Core Driving Principles", items:[
        "Following Distance - Minimum 7 seconds at highway speed. 14 seconds in rain or fog.",
        "Downhill Grades - Select gear before descent. Engine brake first, service brakes second.",
        "Right Turns - Begin wide left, track rear wheels over the curb line, watch trailer swing.",
        "Lane Changes - Signal 3-5 seconds early. Check mirrors three times before moving.",
        "Highway Entry - Match speed before merging. Never force traffic to adjust for you.",
        "Railroad Crossings - Shift to neutral, never shift mid-crossing, check both directions.",
      ]},
      { type:"tip", text:"Look 15 seconds ahead on the highway. That is a quarter mile. If something surprises you at that distance, you had enough time. If you are reacting to something 4 seconds ahead, you are already in trouble." },
      { type:"quiz", q:"What is the minimum following distance recommended at highway speed?", opts:["3 seconds","5 seconds","7 seconds","10 seconds"], ans:2, exp:"FMCSA recommends a minimum of 7 seconds following distance at highway speed for CMVs. This is non-negotiable - at 65 mph you are traveling 95 feet per second." },
    ]},
    { id:"b4", title:"HOS and ELD Basics", icon:"⏱️", duration:"3 min read", xp:80, content:[
      { type:"intro", text:"Hours of Service violations are the number one DOT violation in commercial trucking. Every driver must know these rules cold. An ELD records everything - there is no hiding violations anymore." },
      { type:"steps", title:"The Core HOS Rules for Property Carriers", items:[
        "11-Hour Driving Limit - Maximum 11 hours driving after 10 consecutive hours off duty.",
        "14-Hour On-Duty Limit - Cannot drive after 14 hours from when you went on duty.",
        "30-Minute Break - Required after 8 cumulative hours of driving. Off-duty or sleeper only.",
        "60/70-Hour Rule - 60 hours in 7 days OR 70 hours in 8 days for most carriers.",
        "34-Hour Restart - Reset your 60/70-hour clock with 34 consecutive off-duty hours.",
        "Sleeper Berth Split - 7/3 or 8/2 split allowed but requires careful ELD management.",
      ]},
      { type:"tip", text:"Your 14-hour clock starts the moment you go on duty, even for inspections or fueling. It does not stop for anything except off-duty time. Manage that clock from the first minute of your day or it will manage you." },
      { type:"quiz", q:"What starts the 14-hour on-duty clock?", opts:["When you start driving","When you sign the BOL","The moment you go on duty","When the dispatcher calls"], ans:2, exp:"The 14-hour clock begins the moment you go on duty, regardless of activity. Loading, fueling, pre-trip inspections all count toward your 14-hour window." },
    ]},
    { id:"b5", title:"CDL Test Preparation", icon:"📝", duration:"6 min read", xp:100, content:[
      { type:"intro", text:"The CDL written knowledge test covers general knowledge, air brakes, combination vehicles, and endorsements. Passing requires 80% or higher. Most states allow up to 3 attempts before requiring a waiting period." },
      { type:"steps", title:"Test Day Strategy", items:[
        "General Knowledge - 50 questions, covers all basic CMV operation rules.",
        "Air Brakes - Required if your vehicle has air brakes. 25 questions, must score 80%+.",
        "Combination Vehicles - Required for Class A. 20 questions on coupling, trailers, turning.",
        "Study Method - Take practice tests until you consistently score 90%+ before the real test.",
        "Test Day - Read each question twice. Eliminate obvious wrong answers first.",
        "Common Fails - Air brakes section trips up most beginners. Study it hardest.",
      ]},
      { type:"tip", text:"Take the practice test every single day for 2 weeks before your exam. Not to memorize answers but to understand why each answer is correct. Understanding beats memorization every time on a test with different wording." },
      { type:"quiz", q:"What is the minimum passing score on most CDL knowledge tests?", opts:["70%","75%","80%","85%"], ans:2, exp:"Most states require a minimum score of 80% to pass CDL knowledge tests. Some states and endorsements may require higher scores." },
    ]},

    { id:"b6", title:"Air Brakes Deep Dive", icon:"🛑", duration:"5 min read", xp:90, content:[
      { type:"intro", text:"Air brakes are on virtually every commercial truck. Failing the air brakes portion of your CDL test is an automatic disqualifier. Understanding how air brakes work - not just what to check - is what separates safe drivers from dangerous ones." },
      { type:"steps", title:"How Air Brakes Work", items:[
        "1. Air Compressor - Pumps air into storage tanks. Must build from 50 to 90 PSI in under 3 minutes.",
        "2. Governor - Controls compressor. Cuts in around 100 PSI, cuts out around 125 PSI.",
        "3. Air Tanks - Store compressed air. Drain daily to remove water and oil contamination.",
        "4. Brake Chambers - Air pressure pushes a rod that applies the brakes at each wheel.",
        "5. Slack Adjusters - Connect the push rod to the brake cam. Must not move more than 1 inch by hand.",
        "6. Brake Drums and Shoes - The friction surfaces. Shoes must be at least 1/4 inch thick.",
        "7. Spring Brakes - Emergency and parking brakes held ON by spring pressure, released by air."
      ]},
      { type:"tip", title:"Big Earl Says", text:"Every driver I've seen get in trouble with air brakes ignored the low pressure warning. When that buzzer goes off at 60 PSI, you do NOT keep driving. You find a safe place to stop immediately. Springs will lock those brakes on you and there is nothing you can do about it." },
      { type:"steps", title:"The 5 Air Brake Tests", items:[
        "Test 1 - Build-up: Start engine, should build from 50-90 PSI in under 3 minutes.",
        "Test 2 - Governor check: At 120-125 PSI compressor should cut out.",
        "Test 3 - Warning signal: Turn off engine, pump brakes - warning light/buzzer at 60 PSI.",
        "Test 4 - Spring brake test: Continue pumping - parking brakes should pop on at 20-45 PSI.",
        "Test 5 - Leakdown test: Engine off, release brakes, hold foot brake 1 minute - lose no more than 3 PSI."
      ]},
      { type:"quiz", questions:[
        { q:"What PSI must air pressure build to from 50 PSI in under 3 minutes?", opts:["80 PSI","90 PSI","100 PSI","110 PSI"], ans:1, exp:"Air pressure must build from 50 to 90 PSI in under 3 minutes during the build-up test." },
        { q:"At what PSI should the low air pressure warning activate?", opts:["40 PSI","50 PSI","60 PSI","80 PSI"], ans:2, exp:"The low air pressure warning (buzzer/light) must activate before pressure drops below 60 PSI." },
        { q:"What is the maximum leakdown rate for a combination vehicle with brakes released?", opts:["2 PSI/min","3 PSI/min","4 PSI/min","5 PSI/min"], ans:1, exp:"Air loss must not exceed 3 PSI in one minute with the engine off and brakes released." },
        { q:"Spring brakes automatically activate when air pressure drops to what range?", opts:["60-80 PSI","40-60 PSI","20-45 PSI","10-20 PSI"], ans:2, exp:"Spring brakes activate at 20-45 PSI. At this point the parking/emergency brakes engage automatically." },
      ]},
    ]},
    { id:"b7", title:"Coupling and Uncoupling", icon:"🔗", duration:"4 min read", xp:85, content:[
      { type:"intro", text:"Improper coupling is one of the most dangerous mistakes a CDL driver can make. A trailer that separates at highway speed can kill. The coupling procedure must be done correctly every single time - there are no shortcuts." },
      { type:"steps", title:"Coupling Procedure - 10 Steps", items:[
        "1. Inspect fifth wheel - check for damage, proper lubrication, locking jaws open.",
        "2. Position tractor - back slowly, check mirrors, stop before contact.",
        "3. Check trailer height - trailer should be slightly lower than fifth wheel.",
        "4. Connect air lines and electrical - emergency (red) first, then service (blue).",
        "5. Back under trailer - stop when fifth wheel contacts trailer apron.",
        "6. Test the connection - tug forward against locked trailer brakes.",
        "7. Inspect the lock - visually confirm jaws are around the kingpin.",
        "8. Raise landing gear - crank fully up, secure the crank.",
        "9. Disconnect trailer brake supply - release red valve.",
        "10. Check clearance - ensure trailer clears rear of cab on turns."
      ]},
      { type:"tip", title:"Big Earl Says", text:"The visual check on the jaws is not optional. I have seen drivers do the tug test, feel resistance, and assume they are coupled. They were not. The trailer can seem connected but not be locked. Get out, get under there, and look at those jaws." },
      { type:"quiz", questions:[
        { q:"When coupling, what must you do AFTER backing under the trailer?", opts:["Raise landing gear","Pull forward to test coupling","Connect air lines","Check fifth wheel grease"], ans:1, exp:"Always perform the tug test by pulling forward against locked trailer brakes to verify the coupling is secure before doing anything else." },
        { q:"The kingpin locking jaws must be visually confirmed to be:", opts:["Partially closed","Fully open","Fully closed around kingpin","Greased and open"], ans:2, exp:"Jaws must be fully closed around the kingpin. The visual check is mandatory - the tug test alone is not sufficient." },
        { q:"What color is the emergency air line glad hand?", opts:["Blue","Yellow","Red","Green"], ans:2, exp:"Red is emergency, blue is service. Connect emergency (red) first, service (blue) second." },
        { q:"Landing gear must be in what position before driving?", opts:["Partially raised","Fully raised and crank secured","Lowered for stability","It does not matter"], ans:1, exp:"Landing gear must be fully raised and the crank handle secured before moving." },
      ]},
    ]},
    { id:"b8", title:"Hazmat Awareness", icon:"☢️", duration:"4 min read", xp:80, content:[
      { type:"intro", text:"Even if you never plan to haul hazmat, you need to recognize it, know the placarding rules, and understand your legal responsibilities when you encounter it. Many loads are borderline hazmat without drivers knowing it." },
      { type:"steps", title:"The 9 Hazmat Classes", items:[
        "Class 1 - Explosives (dynamite, fireworks, ammunition)",
        "Class 2 - Gases (compressed, liquefied, or dissolved gas)",
        "Class 3 - Flammable Liquids (gasoline, fuel oil, paint)",
        "Class 4 - Flammable Solids (matches, metal powders)",
        "Class 5 - Oxidizers and Organic Peroxides",
        "Class 6 - Poisons and Infectious Substances",
        "Class 7 - Radioactive Materials",
        "Class 8 - Corrosives (battery acid, bleach)",
        "Class 9 - Miscellaneous Hazardous Materials"
      ]},
      { type:"steps", title:"Placarding Rules", items:[
        "1,001 lbs or more of most hazmat requires diamond-shaped placards on all 4 sides.",
        "ANY amount of Class 1, 2.3, 4.3, 6.1 (Poison Inhalation Hazard), 7, or dangerous requires placards.",
        "Shipping papers must be within reach of driver at all times - left side door pocket.",
        "Emergency response guidebook must be in the cab."
      ]},
      { type:"tip", title:"Big Earl Says", text:"If a shipper hands you a load and you see a placard on the freight but no shipping papers - stop right there. Do not move that truck. You are responsible for what is in that trailer once you sign for it." },
      { type:"quiz", questions:[
        { q:"Which hazmat class covers flammable liquids like gasoline?", opts:["Class 1","Class 2","Class 3","Class 4"], ans:2, exp:"Class 3 covers flammable liquids including gasoline, fuel oil, and paint." },
        { q:"Shipping papers must be kept where while driving?", opts:["In the trailer","In the glove box","Within reach of driver - left door pocket","At the carrier office"], ans:2, exp:"Shipping papers must be within reach of the driver at all times, typically in the left door pocket." },
        { q:"How many pounds of most hazmat require placards on all 4 sides?", opts:["500 lbs","750 lbs","1,001 lbs","2,000 lbs"], ans:2, exp:"1,001 lbs or more of most hazardous materials requires diamond-shaped placards on all four sides of the vehicle." },
        { q:"Which hazmat class requires placards regardless of quantity?", opts:["Class 3","Class 8","Class 6","Class 2.3 Poison Inhalation Hazard"], ans:3, exp:"Class 2.3 (Poison Inhalation Hazard) requires placards for ANY amount, no minimum weight threshold." },
      ]},
    ]},
    { id:"b9", title:"Mountain and Grade Driving", icon:"⛰️", duration:"4 min read", xp:85, content:[
      { type:"intro", text:"More truckers die on mountain grades than almost any other driving situation. Brake fade is real. Runaway trucks are real. Every driver who ever gets near a mountain pass needs to understand exactly what happens when you use your brakes wrong going downhill." },
      { type:"steps", title:"Descending Grades Safely", items:[
        "1. Check your speed BEFORE the descent - posted speed for trucks is your maximum, not your target.",
        "2. Select the right gear BEFORE the descent - same gear you would use going up.",
        "3. Use the brake application method - apply firm pressure, slow to 5 mph BELOW safe speed, release.",
        "4. Let brakes cool between applications - continuous braking causes brake fade.",
        "5. Never ride the brakes - friction heat boils brake fluid and glazes drums.",
        "6. Watch for runaway truck ramps - they exist because people miscalculate. Use them if needed.",
        "7. Engine brake (Jake brake) - use to slow without heat buildup. Check local signs."
      ]},
      { type:"tip", title:"Big Earl Says", text:"The gear you go up in is the gear you go down in. I do not care what anyone else tells you. That is the rule. And if you feel your brakes starting to fade - they feel soft, the truck is not slowing down right - that runaway truck ramp is not embarrassing. It is the right call every time." },
      { type:"quiz", questions:[
        { q:"What gear should you use going down a steep grade?", opts:["One gear higher than going up","Same gear as going up","Neutral to save fuel","Highest gear possible"], ans:1, exp:"Select the same gear going down as you would use going up. This prevents brake overheating." },
        { q:"What is brake fade caused by?", opts:["Too much air pressure","Continuous braking creating heat","Brakes that are too tight","Cold weather"], ans:1, exp:"Continuous braking generates friction heat that boils brake fluid and glazes drums, causing fade - brakes stop working." },
        { q:"The correct mountain braking method is:", opts:["Ride brakes continuously","Apply firm pressure, slow 5 mph below target, release, repeat","Use only engine brake","Stay in highest gear possible"], ans:1, exp:"Apply brakes firmly, slow to 5 mph below safe speed, release to let brakes cool, then repeat as needed." },
        { q:"A runaway truck ramp should be used when:", opts:["You are running late","You feel your brakes fading and cannot control speed","Traffic is too heavy","Your dispatcher says to"], ans:1, exp:"Use the ramp any time brakes are fading and you cannot control your speed. It is always the right call - never embarrassing." },
      ]},
    ]},
    { id:"b10", title:"Night and Weather Driving", icon:"🌧️", duration:"4 min read", xp:75, content:[
      { type:"intro", text:"Driving conditions that would be manageable in a car become life-threatening in a loaded 80,000 lb truck. Your stopping distance, your visibility, and your reaction time requirements all change dramatically in adverse conditions." },
      { type:"steps", title:"Night Driving Rules", items:[
        "1. Use high beams when no oncoming traffic - you need every foot of visibility.",
        "2. Drive to your headlight range - if you can see 400 feet, your stopping distance must be under 400 feet.",
        "3. Clean all lights before dark - dirty marker lights are invisible to other drivers.",
        "4. Watch for deer at dusk and dawn - most animal strikes happen in low-light transitions.",
        "5. Take rest breaks - fatigue hits hardest between midnight and 6 AM."
      ]},
      { type:"steps", title:"Weather Driving Rules", items:[
        "Rain: Reduce speed 1/3. Increase following distance. Watch for hydroplaning at highway speeds.",
        "Snow/Ice: Reduce speed by half minimum. Black ice is invisible - treat all dark pavement as ice.",
        "Wind: Loaded trailers act as sails. High profile loads need wind speed awareness.",
        "Fog: Use low beams - high beams reflect back and blind you. If visibility under 100 feet, pull over."
      ]},
      { type:"tip", title:"Big Earl Says", text:"There is no load worth dying for. If the weather is bad enough that you are white-knuckling it, you are already past the point where you should have pulled over. A dispatcher who pressures you to drive through dangerous conditions is asking you to break the law - you have the right to refuse." },
      { type:"quiz", questions:[
        { q:"In rain, you should reduce speed by approximately:", opts:["10%","25%","One third","One half"], ans:2, exp:"In rain reduce speed by at least one third. A truck that stops in 300 feet dry may need 450+ feet in wet conditions." },
        { q:"In fog with visibility under 100 feet, you should:", opts:["Use high beams","Use low beams and slow down","Pull over and stop","Flash hazards and continue"], ans:2, exp:"Pull over when visibility drops below 100 feet. High beams reflect back in fog and reduce visibility further." },
        { q:"Which type of pavement is most dangerous and invisible to drivers?", opts:["Wet concrete","Gravel","Black ice","Packed snow"], ans:2, exp:"Black ice is a thin transparent layer of ice that looks like wet pavement. It is invisible and extremely slippery." },
        { q:"When driving at night, you should:", opts:["Drive faster to reduce exposure","Always use high beams","Drive within your headlight range","Ignore the speed limit"], ans:2, exp:"Drive to your headlight range - if you can see 400 feet ahead, your stopping distance must be under 400 feet." },
      ]},
    ]},
    { id:"b11", title:"Hours of Service Deep Dive", icon:"⏰", duration:"5 min read", xp:90, content:[
      { type:"intro", text:"HOS violations are the number one way drivers lose their CDL and get carriers fined. The rules seem complicated but they follow a clear logic once you understand the framework. Learn these cold - a DOT officer will test you on them." },
      { type:"steps", title:"The 4 Key HOS Rules", items:[
        "11-Hour Rule - May drive maximum 11 hours after 10 consecutive hours off duty.",
        "14-Hour Rule - May not drive beyond the 14th hour after coming on duty. Cannot extend with breaks.",
        "30-Minute Break - Must take 30-minute break after 8 hours of driving time.",
        "60/70-Hour Rule - Cannot drive after 60 hours on duty in 7 days OR 70 hours in 8 days."
      ]},
      { type:"steps", title:"Resets and Exceptions", items:[
        "34-Hour Restart - Reset 60/70 hour clock with 34 consecutive hours off duty.",
        "Sleeper Berth Split - Can split required 10 hours rest into two periods (8+2 or 7+3).",
        "Short-Haul Exception - Drivers within 150 air miles of home terminal may skip ELD in some cases.",
        "Adverse Conditions - May extend 11-hour limit by 2 hours if conditions develop unexpectedly."
      ]},
      { type:"tip", title:"Big Earl Says", text:"The 14-hour clock is the one that gets people. It does not stop when you take a break. Once it starts it runs straight through. So if you start your day at 6 AM, at 8 PM you are done driving - period. Plan your day around that clock, not around your miles." },
      { type:"quiz", questions:[
        { q:"The maximum driving time allowed per shift is:", opts:["10 hours","11 hours","12 hours","14 hours"], ans:1, exp:"You may drive a maximum of 11 hours after 10 consecutive hours off duty." },
        { q:"The 14-hour window starts when:", opts:["You start driving","You leave the terminal","You come on duty","You take your first break"], ans:2, exp:"The 14-hour clock starts when you first come on duty - not when you start driving. Breaks do not pause it." },
        { q:"What is required after 8 hours of driving?", opts:["A 30-minute break","A 1-hour break","10 hours off duty","Nothing is required"], ans:0, exp:"A 30-minute break is required after 8 cumulative hours of driving time." },
        { q:"A 34-hour restart resets which clock?", opts:["The 11-hour driving limit","The 14-hour window","The 60/70-hour on-duty limit","The sleeper berth split"], ans:2, exp:"A 34-hour restart resets the 60/70-hour on-duty clock, allowing you to start a new duty cycle." },
      ]},
    ]},
    { id:"b12", title:"Roadside Inspections and DOT", icon:"👮", duration:"4 min read", xp:80, content:[
      { type:"intro", text:"Every commercial driver will be inspected at some point. The CVSA conducts over 3 million inspections per year. Knowing what inspectors look for - and what puts you out of service - is essential knowledge before your first mile." },
      { type:"steps", title:"The 6 Levels of Inspection", items:[
        "Level 1 - Full inspection: Driver and vehicle. Most thorough. Takes 45-60 minutes.",
        "Level 2 - Walk-around: Inspector walks around but does not go under vehicle.",
        "Level 3 - Driver only: License, medical card, HOS logs, seatbelt.",
        "Level 4 - Special study: Specific item being studied for safety data.",
        "Level 5 - Vehicle only: No driver present required.",
        "Level 6 - Radiological: For vehicles hauling radioactive materials."
      ]},
      { type:"steps", title:"Top Out-of-Service Violations", items:[
        "1. HOS violations - falsified or insufficient hours of service.",
        "2. Brake violations - out of adjustment, air leaks, missing components.",
        "3. Tire violations - tread depth below minimums, flat tires, exposed cords.",
        "4. Lighting violations - brake lights, head lights, marker lights not working.",
        "5. Cargo securement - improper tie-downs, overweight, unsecured load.",
        "6. Driver condition - fatigue, impairment, missing medical certificate."
      ]},
      { type:"tip", title:"Big Earl Says", text:"When a DOT officer pulls you over, be professional, be respectful, and have your documents organized and ready. License, medical card, registration, IFTA, BOL, and your last 8 days of logs. Do not be searching around. That alone tells an inspector something." },
      { type:"quiz", questions:[
        { q:"A Level 1 inspection is:", opts:["Vehicle only","Driver only","Full driver and vehicle inspection","Hazmat specific only"], ans:2, exp:"Level 1 is a full inspection covering both driver credentials and the entire vehicle. It takes 45-60 minutes." },
        { q:"Which violation most commonly puts drivers out of service?", opts:["Dirty truck","Broken CB radio","HOS violations and brake defects","Missing coffee thermos"], ans:2, exp:"HOS violations and brake defects are the top out-of-service violations during DOT inspections." },
        { q:"During a DOT stop, what documents must be ready?", opts:["Just your license","License and medical card only","License, medical card, registration, IFTA, BOL, and 8 days of logs","Only your ELD"], ans:2, exp:"Have all documents organized: license, medical card, registration, IFTA, bill of lading, and last 8 days of logs." },
        { q:"A drug and alcohol test is federally required after an accident with:", opts:["Any fender bender","Only fatalities","Injury, fatality, or vehicle towed","Only if police request it"], ans:2, exp:"Federal law requires drug and alcohol testing within 8 hours after accidents involving injury, fatality, or a towed vehicle." },
      ]},
    ]},
  ],
  company:[
    { id:"c1", title:"Advanced Trip Planning", icon:"🗺️", duration:"2 min read", xp:50, content:[
      { type:"intro", text:"Professional trip planning adds 10-20% to your earnings annually. It is the difference between a driver who reacts and one who profits. Every mile of deadhead, every missed appointment, every fuel stop at the wrong place costs real money." },
      { type:"steps", title:"The Professional Planning Checklist", items:[
        "Load Review - Study the BOL, special handling notes, receiver hours before accepting.",
        "Route Planning - PC Miler or Rand McNally only. Google Maps will get you killed on a bridge.",
        "Fuel Strategy - Plan stops 300-350 miles apart. Check truck stop diesel prices via apps.",
        "HOS Math - Calculate arrival time with required breaks built in before you leave.",
        "Weather Window - Check mountain pass forecasts 24 hours out. Have an alternate route.",
        "Receiver Recon - Call ahead on long hauls. Know the dock number, check-in procedure.",
      ]},
      { type:"tip", text:"I plan every trip the night before. Route, fuel, rest stops, receiver contact. When problems hit at 3am on I-70 in Colorado, the driver who planned survives. The driver who winged it is calling dispatch in a panic." },
      { type:"quiz", q:"What tool should professional truck drivers use for routing?", opts:["Google Maps","Apple Maps","PC Miler or Rand McNally","Waze"], ans:2, exp:"Commercial truck routing software like PC Miler or Rand McNally accounts for vehicle height, weight, and hazmat restrictions. Consumer GPS apps route you into low bridges and restricted roads." },
    ]},
    { id:"c2", title:"Defensive Driving for CMVs", icon:"🛡️", duration:"2 min read", xp:75, content:[
      { type:"intro", text:"In a crash between a semi and a car, the driver of the semi is assumed at fault by insurance companies, law enforcement, and juries - even when the car driver caused it. You must drive defensively enough for both vehicles." },
      { type:"steps", title:"Professional Defensive Driving Principles", items:[
        "Smith System - Aim high in steering, get the big picture, keep your eyes moving.",
        "Space Cushion - Maintain buffers on all 4 sides. Merge into your space, never beside another truck.",
        "Four-Wheeler Behavior - Predict blind spot merges. Expect cars to cut you off at exits.",
        "Adverse Weather Protocol - Reduce speed 25% in rain, 50% in snow. No exceptions.",
        "Fatigue Recognition - If you yawn 3 times in 5 minutes, pull over. Sleep deprivation kills.",
        "Distracted Driving - Federal law bans hand-held phone use while driving CMV. Period.",
      ]},
      { type:"tip", text:"Assume every four-wheeler driver cannot see you. Because most of the time they cannot. Your blind spots are enormous. A car in your right blind spot does not exist until you look for it." },
      { type:"quiz", q:"Approximately how much should you reduce speed in snowy conditions?", opts:["10%","25%","50%","You should not drive in snow"], ans:2, exp:"FMCSA recommends reducing speed by approximately 50% in snow and ice. A truck that cannot stop safely should not be moving at highway speed regardless of schedule pressure." },
    ]},
    { id:"c3", title:"Dock and Shipper Relations", icon:"🤝", duration:"2 min read", xp:40, content:[
      { type:"intro", text:"Your reputation at docks travels faster than you do. The drivers who get loaded first, get the good freight, and get helped when things go wrong are the ones who treat dock workers with respect every single time." },
      { type:"steps", title:"Professional Dock Conduct", items:[
        "Check-In Right - Know the procedure before you arrive. Guard shack, door office, or app.",
        "BOL Accuracy - Count your pieces. Note damage before signing. This is your legal protection.",
        "Dock Patience - Dock workers control your time. Attitude costs you hours.",
        "Seal Procedures - Record seal numbers on your BOL and photograph them.",
        "Detention Tracking - Log your arrival time immediately. Detention pay requires documentation.",
        "Professionalism - Clean cab, professional appearance. You represent your company every time.",
      ]},
      { type:"tip", text:"I have been loaded in 20 minutes at docks where other drivers waited 4 hours. The difference was treating the dock crew like they matter - because they do. One friendly driver gets remembered. One rude driver gets remembered longer." },
      { type:"quiz", q:"What should you do before signing the Bill of Lading?", opts:["Sign it and check later","Count pieces and note any damage first","Just accept what the shipper says","Call your dispatcher first"], ans:1, exp:"Always physically count pieces and note any pre-existing damage on the BOL before signing. Once you sign, you are legally responsible for the freight exactly as described." },
    ]},
    { id:"c4", title:"Roadside Inspections", icon:"🚔", duration:"2 min read", xp:65, content:[
      { type:"intro", text:"FMCSA roadside inspections affect your CSA score, your company's score, and your ability to get hired. A Level 1 inspection takes 45-60 minutes but a clean inspection improves your score. Know what inspectors look for." },
      { type:"steps", title:"DOT Inspection Levels", items:[
        "Level 1 - Full inspection: driver, vehicle, cargo. Most common at weigh stations.",
        "Level 2 - Walk-around only, no under-vehicle check. Common at roadside pulloffs.",
        "Level 3 - Driver only: license, HOS logs, medical cert, seatbelt, drug/alcohol.",
        "Level 4 - Special study inspection. Targeted for research purposes.",
        "Level 5 - Vehicle-only inspection. Usually at terminals with no driver present.",
        "Always have ready: CDL, medical cert, registration, insurance, IFTA decals, ELD.",
      ]},
      { type:"tip", text:"Be polite, be prepared, and be professional. Inspectors have discretion. A cooperative driver with minor issues often gets a warning. A hostile driver with the same issues gets every citation written up. Your attitude is part of the inspection." },
      { type:"quiz", q:"Which CSA Behavior Analysis category carries the most weight?", opts:["Vehicle Maintenance","Unsafe Driving","HOS Compliance","Driver Fitness"], ans:1, exp:"Unsafe Driving violations carry the highest severity weights in the CSA scoring system, including speeding, reckless driving, and improper lane changes." },
    ]},

    { id:"c5", title:"Cargo Securement", icon:"📦", duration:"4 min read", xp:85, content:[
      { type:"intro", text:"Unsecured cargo kills people. A shifting load can flip your truck or shed debris that kills other drivers. FMCSA cargo securement rules are detailed and specific - and DOT inspectors check them at every Level 1 inspection." },
      { type:"steps", title:"Working Load Limit Rules", items:[
        "Aggregate WLL of all tie-downs must equal at least half the cargo weight.",
        "Cargo up to 10 feet long: minimum 2 tie-downs regardless of weight.",
        "Each additional 10 feet of cargo: add 1 more tie-down.",
        "Tie-downs must prevent forward, rearward, sideways, and vertical movement.",
        "Binders must be sealed or locked - vibration can open unsecured binders."
      ]},
      { type:"steps", title:"Special Cargo Rules", items:[
        "Flatbed steel: Edge protection required where straps contact metal.",
        "Lumber: Cannot extend more than 1/3 of load length beyond rear of trailer.",
        "Logs: Must use stakes, wrappers, or bolsters rated for the load weight.",
        "Vehicles: Must be chocked or secured at all 4 tires plus chain.",
        "Oversized: Requires escort, permits, and flags before moving."
      ]},
      { type:"tip", title:"Big Earl Says", text:"Do a cargo check every 150 miles or at every stop. Straps loosen. Loads shift. A strap that was tight at the dock in Memphis may be hanging loose by the time you hit Little Rock. It takes 5 minutes and it can be the difference between a normal delivery and a fatality." },
      { type:"quiz", questions:[
        { q:"The aggregate Working Load Limit of all tie-downs must equal at least:", opts:["One quarter of cargo weight","One third of cargo weight","One half of cargo weight","Full cargo weight"], ans:2, exp:"Total WLL of all securement devices must equal at least half the weight of the cargo being secured." },
        { q:"Cargo up to 10 feet long requires a minimum of how many tie-downs?", opts:["1","2","3","4"], ans:1, exp:"A minimum of 2 tie-downs is required regardless of weight for cargo up to 10 feet in length." },
        { q:"When should you perform a cargo check after departure?", opts:["Never - dock workers handle it","Every 500 miles","Every 150 miles or at each stop","Only at destination"], ans:2, exp:"Check cargo every 150 miles or at every stop. Straps loosen with vibration and loads shift during transport." },
        { q:"Edge protection is required when:", opts:["Always","Only on flatbeds","When straps contact metal edges","Only for heavy cargo"], ans:2, exp:"Edge protection must be used wherever tie-down straps contact sharp metal edges to prevent cutting and failure." },
      ]},
    ]},
    { id:"c6", title:"ELD Compliance and Violations", icon:"📱", duration:"5 min read", xp:90, content:[
      { type:"intro", text:"Since December 2017, most commercial drivers are required to use an Electronic Logging Device. The ELD mandate eliminated paper log fraud but created new compliance challenges. Understanding exactly what your ELD tracks - and what triggers violations - protects your CDL and your paycheck." },
      { type:"steps", title:"What Your ELD Tracks", items:[
        "Engine hours and vehicle movement - automatically records when truck moves.",
        "Driving status - auto-switches to Driving when truck exceeds 5 mph.",
        "Location - recorded at every change of duty status.",
        "Unassigned miles - any movement without a logged-in driver flags as unassigned.",
        "Edit history - every manual edit is recorded and timestamped. Inspectors see all edits."
      ]},
      { type:"steps", title:"Common ELD Violations", items:[
        "1. Unassigned driving - miles recorded but not assigned to a driver.",
        "2. Personal conveyance misuse - using PC status for business movements.",
        "3. Form and manner errors - missing required fields (home terminal, carrier info).",
        "4. Failure to transfer data - inability to send logs to inspector via email or display.",
        "5. Driving during off-duty - ELD shows movement during logged off-duty period."
      ]},
      { type:"tip", title:"Big Earl Says", text:"Personal conveyance is for personal use only. I know dispatchers who tell drivers to use PC to reposition the truck to a better drop spot. That is illegal. If the company benefits from the movement, it is on duty. Use PC wrong enough times and you will get a warning letter from FMCSA." },
      { type:"quiz", questions:[
        { q:"Your ELD automatically switches to Driving status when your truck exceeds:", opts:["0 mph","3 mph","5 mph","10 mph"], ans:2, exp:"The ELD automatically records Driving status when the vehicle exceeds 5 mph. You cannot manually override this." },
        { q:"Personal conveyance (PC) status is legal when:", opts:["Repositioning truck for the company","Driving to a shipper pickup","Going to a personal destination while off duty","Any slow-speed movement"], ans:2, exp:"PC is only for personal use while off duty. Any movement that benefits the carrier is on-duty and must be logged." },
        { q:"ELD edit history is:", opts:["Deleted after 30 days","Visible only to the carrier","Permanently recorded and visible to inspectors","Automatically corrected"], ans:2, exp:"Every manual edit is permanently timestamped and recorded. DOT inspectors can see all edits during an inspection." },
        { q:"Unassigned driving on your ELD means:", opts:["You drove with a co-driver","Miles were recorded with no logged-in driver","You used personal conveyance","Your ELD had a malfunction"], ans:1, exp:"Unassigned miles are recorded vehicle movement with no driver logged in. These flag as violations during inspections." },
      ]},
    ]},
    { id:"c7", title:"Accident Procedures", icon:"🚨", duration:"4 min read", xp:85, content:[
      { type:"intro", text:"How you handle the first 15 minutes after an accident will affect everything that follows - your job, your CDL, potential lawsuits, and criminal liability. Most drivers have never been trained on what to actually do. This lesson changes that." },
      { type:"steps", title:"Immediate Response - In Order", items:[
        "1. Check for injuries - your safety first, then others. Do not move injured people unless in immediate danger.",
        "2. Secure the scene - hazard lights on, set triangles at 10, 100, and 200 feet behind truck.",
        "3. Call 911 - even minor accidents involving a commercial vehicle may require police.",
        "4. Notify your carrier immediately - company safety department must be contacted before you talk to anyone else.",
        "5. Document everything - photos of all vehicles, road conditions, skid marks, traffic signs, witness names.",
        "6. Do NOT admit fault - say nothing about what happened to anyone except police and your carrier.",
        "7. Drug and alcohol test - federally required within 8 hours of any accident with injury, fatality, or vehicle towed."
      ]},
      { type:"tip", title:"Big Earl Says", text:"The other driver will have an attorney within 48 hours. Your carrier's insurance company is not your friend either - they want to minimize payout. Your only job at the scene is: secure it, document it, say nothing. Let the lawyers and investigators do the rest." },
      { type:"quiz", questions:[
        { q:"After an accident, your FIRST priority is:", opts:["Call your dispatcher","Take photos","Check for injuries and secure the scene","Call an attorney"], ans:2, exp:"Check for injuries and secure the scene first - hazards on, triangles out. Then notify your carrier before anyone else." },
        { q:"At an accident scene, you should tell other drivers:", opts:["Exactly what happened","Nothing about the accident itself","Your insurance policy number","Your carrier's phone number"], ans:1, exp:"Do not admit fault or describe what happened to anyone except police and your carrier's safety department." },
        { q:"A post-accident drug test is required within:", opts:["2 hours for alcohol, 32 hours for drugs","8 hours for alcohol, 32 hours for drugs","24 hours for both","Only if requested by police"], ans:1, exp:"Federal regulations require alcohol testing within 2 hours and drug testing within 32 hours after a qualifying accident." },
        { q:"Triangles should be placed at:", opts:["10, 50, 100 feet","10, 100, 200 feet","50, 100, 500 feet","25, 50, 100 feet"], ans:1, exp:"Place warning triangles at 10 feet (immediate), 100 feet (approaching), and 200 feet behind the vehicle." },
      ]},
    ]},
    { id:"c8", title:"Driver Health and Fatigue", icon:"💪", duration:"4 min read", xp:70, content:[
      { type:"intro", text:"Fatigued driving kills. FMCSA estimates 13% of commercial truck accidents involve a fatigued driver. But fatigue is not just about hours - diet, hydration, sleep quality, and mental health all affect your ability to drive safely and maintain your medical certification." },
      { type:"steps", title:"Fatigue Warning Signs", items:[
        "Difficulty keeping eyes open or focused - immediate stop required.",
        "Missing exits or signs you just passed - your brain is already micro-sleeping.",
        "Drifting between lanes or hitting rumble strips.",
        "Inability to remember the last few miles.",
        "Irritability or aggression - emotional regulation drops before physical control."
      ]},
      { type:"steps", title:"Staying Healthy on the Road", items:[
        "Sleep: 7-9 hours in your sleeper counts - but cab temperature, noise, and light matter.",
        "Diet: Protein and fat keep you alert. Sugar and simple carbs cause energy crashes.",
        "Hydration: Dehydration causes fatigue. Drink water, not just coffee.",
        "Exercise: Even 15 minutes of walking at each stop improves circulation and alertness.",
        "DOT Medical: Keep blood pressure, blood sugar, and vision in compliance or you lose your card."
      ]},
      { type:"tip", title:"Big Earl Says", text:"I drove tired for years because I thought it was toughness. It is not. It is stupidity. I put other people in danger because I wanted to make miles. The day I found myself driving and not remembering the last exit was the day I started taking 10-minute nap breaks seriously. Power naps work." },
      { type:"quiz", questions:[
        { q:"FMCSA estimates what percentage of commercial truck accidents involve a fatigued driver?", opts:["5%","13%","20%","25%"], ans:1, exp:"FMCSA estimates approximately 13% of commercial truck accidents involve driver fatigue as a contributing factor." },
        { q:"Which is the most dangerous time of day for fatigue?", opts:["Mid-morning","Early afternoon","Midnight to 6 AM","Late evening"], ans:2, exp:"Fatigue is most severe between midnight and 6 AM due to natural circadian rhythm dips in alertness." },
        { q:"Missing exits you just passed is a warning sign of:", opts:["GPS malfunction","Micro-sleeping","Distracted driving","Caffeine overdose"], ans:1, exp:"Missing recent exits means your brain is already micro-sleeping - brief unconscious periods. Stop immediately." },
        { q:"The recommended strategy for managing fatigue on long runs is:", opts:["Drink more coffee","Take 10-20 minute power naps at rest stops","Drive faster to finish sooner","Use stimulant supplements"], ans:1, exp:"Short 10-20 minute power naps are scientifically proven to restore alertness better than caffeine alone." },
      ]},
    ]},
    { id:"c9", title:"Professional Communication", icon:"📞", duration:"3 min read", xp:65, content:[
      { type:"intro", text:"Your ability to communicate professionally with dispatchers, shippers, receivers, and DOT officers directly affects your pay, your career, and your safety. Drivers who communicate well get the best loads. Drivers who burn bridges get the worst ones." },
      { type:"steps", title:"Communicating with Dispatch", items:[
        "Report problems early - a dispatcher cannot help you if you tell them at the last minute.",
        "Be specific - do not say 'I am running late.' Say 'I will be 2 hours late due to traffic backup on I-40.'",
        "Ask questions before accepting a load - know the rate, pickup and delivery windows, and any special requirements.",
        "Document everything in writing - follow verbal agreements with a text or message.",
        "Push back professionally - if a load is unsafe or illegal, say so clearly and calmly."
      ]},
      { type:"steps", title:"At the Dock", items:[
        "Call ahead - always call the receiver 30-60 minutes before arrival.",
        "Check in immediately - introduce yourself, have your paperwork ready.",
        "Stay professional during delays - dock workers and receivers remember difficult drivers.",
        "Inspect the load before signing - note any damage on the BOL before your signature."
      ]},
      { type:"tip", title:"Big Earl Says", text:"Your reputation follows you in this industry. Dispatchers talk to each other. Dock managers remember who was professional and who made their day harder. The driver who calls ahead, shows up on time, and handles problems without drama gets offered the premium loads." },
      { type:"quiz", questions:[
        { q:"When reporting a delay to dispatch, you should say:", opts:["I am running late","I will be 2 hours late due to I-40 backup near Memphis","No problem, I will figure it out","Wait until you arrive"], ans:1, exp:"Always give specific information: how late, where you are, and the reason. Dispatchers need details to help you." },
        { q:"Before signing a Bill of Lading at pickup, you should:", opts:["Sign quickly to save time","Inspect and note any existing damage first","Trust the shipper's count","Only check the weight"], ans:1, exp:"Always inspect cargo before signing. Note any damage, discrepancies, or issues on the BOL before your signature - you own it after signing." },
        { q:"When should you call a receiver before delivery?", opts:["Only if you are late","30-60 minutes before arrival","When you arrive","Dispatch handles all calls"], ans:1, exp:"Call 30-60 minutes before arrival. Dock workers and receivers can prepare and your professionalism is noticed and remembered." },
        { q:"If a dispatcher pressures you to violate HOS rules, you should:", opts:["Comply to keep your job","Refuse clearly and document it","Ask another driver to cover","Ignore them and drive anyway"], ans:1, exp:"You have the legal right to refuse. Document the request in writing. HOS violations are your license and your liability, not theirs." },
      ]},
    ]},
    { id:"c10", title:"Fuel Management and Trip Planning", icon:"⛽", duration:"4 min read", xp:75, content:[
      { type:"intro", text:"Fuel is your single largest operating expense whether you own your truck or not. A company driver who plans their fuel stops saves the company money - and that gets noticed at review time. An owner-operator who fuels wrong can lose thousands of dollars a year." },
      { type:"steps", title:"Smart Fueling Strategy", items:[
        "Fuel at lowest-cost states - California, Pennsylvania, and New York diesel is consistently expensive.",
        "Use fuel cards - carrier fuel cards often include discounts of 10-40 cents per gallon.",
        "Never run below 1/4 tank in remote areas - mountain routes can have 100+ miles between stops.",
        "Fuel at truck stops, not highway gas stations - scales, parking, and restrooms matter.",
        "Top off before sleep - fuel prices change overnight. Lock in the current price."
      ]},
      { type:"steps", title:"Trip Planning Basics", items:[
        "Plan your route before dispatch confirms - know your HOS window and whether the load is achievable.",
        "Identify rest stops in advance - running out of HOS with nowhere legal to park is a violation.",
        "Check size and weight restrictions - some routes restrict oversized loads by time of day.",
        "Check weather for entire route - not just your current location.",
        "Have a backup plan - what do you do if your receiver is closed or has no dock appointment?"
      ]},
      { type:"tip", title:"Big Earl Says", text:"The drivers who make the most money are not the fastest drivers. They are the best planners. They know where they are stopping for fuel 300 miles ahead. They know what the weather is doing across 3 states. They do not react to problems - they anticipate them." },
      { type:"quiz", questions:[
        { q:"Which states consistently have the highest diesel fuel prices?", opts:["Texas and Oklahoma","California and Pennsylvania","Florida and Georgia","Nevada and Utah"], ans:1, exp:"California and Pennsylvania consistently rank among the highest diesel prices. Texas and New Jersey are typically among the lowest." },
        { q:"What is the recommended minimum fuel level before entering remote mountain routes?", opts:["Empty to 1/8 tank","1/8 to 1/4 tank","1/4 tank minimum","1/2 tank minimum"], ans:2, exp:"Never drop below 1/4 tank before remote routes. Mountain corridors can have 100+ miles between fuel stops." },
        { q:"The best time to plan your rest stop locations is:", opts:["When you run out of hours","At the end of your shift","Before you accept the load","When dispatch calls"], ans:2, exp:"Plan rest stops before you accept the load. Running out of hours with nowhere legal to park is a violation and a safety risk." },
        { q:"Carrier fuel cards typically offer savings of:", opts:["1-3 cents per gallon","5-10 cents per gallon","10-40 cents per gallon","50+ cents per gallon"], ans:2, exp:"Carrier fuel cards often include network discounts of 10-40 cents per gallon, saving thousands annually." },
      ]},
    ]},
  ],
  owner:[
    { id:"o1", title:"Starting Your Business", icon:"🚀", duration:"3 min read", xp:100, content:[
      { type:"intro", text:"You are not just becoming a truck driver. You are becoming a business owner. The drivers who fail in year one almost always fail for business reasons, not driving reasons. Set up the business right before you haul a single load." },
      { type:"steps", title:"Business Setup Sequence", items:[
        "Form an LLC - File with your state ($50-500). Separates personal and business liability.",
        "Get EIN - Free at IRS.gov. Required for business banking, taxes, and authority applications.",
        "Business Bank Account - Never mix personal and business money. Ever.",
        "DOT Number - Required for interstate commerce. Apply at FMCSA.dot.gov, free.",
        "MC Authority - Form OP-1, costs $300. Required to haul for hire.",
        "BOC-3 Filing - Process agent required before authority activates.",
        "UCR Registration - Unified Carrier Registration, required annually by state.",
      ]},
      { type:"tip", text:"The LLC is not optional. If your truck is in your personal name and you have an at-fault accident, they sue you personally. Your house, your savings, your retirement - all exposed. Spend the $200 and form the LLC before you move an inch." },
      { type:"quiz", q:"What is the main financial protection an LLC provides?", opts:["Lower fuel costs","Tax-free income","Separation of personal and business liability","Free DOT registration"], ans:2, exp:"An LLC creates a legal separation between your personal assets and business liabilities. If the business is sued, your personal home, car, and savings are protected." },
    ]},
    { id:"o2", title:"Understanding Your Numbers", icon:"💰", duration:"3 min read", xp:90, content:[
      { type:"intro", text:"Most owner-operators who fail do not fail because they are bad drivers. They fail because they do not know their cost per mile. You cannot price a load profitably if you do not know what it costs you to move it." },
      { type:"steps", title:"The Real Cost Per Mile Breakdown", items:[
        "Fuel - 45-65 cents per mile. Your biggest variable cost. Track MPG obsessively.",
        "Truck Payment - 15-30 cents per mile if financed. Cash trucks change your math entirely.",
        "Insurance - 10-20 cents per mile. New authority pays more. Clean record pays less.",
        "Tires - 3-5 cents per mile. Budget $500-700 per drive tire, $350 per trailer tire.",
        "Maintenance - 10-15 cents per mile. Preventive maintenance is always cheaper than emergency.",
        "Tolls, Permits, Misc - 3-8 cents per mile depending on lanes.",
        "Total All-In Cost - Budget $1.65-2.10 per mile. Never accept less than your break-even.",
      ]},
      { type:"tip", text:"Write your cost per mile number down and tape it inside your cab. When a broker offers you a rate, the first question is not whether it is fair - it is whether it covers your costs. Hauling for less than your cost per mile is not a business, it is a slow bankruptcy." },
      { type:"quiz", q:"What is the most important number every owner-operator must know?", opts:["Gross revenue per week","Cost per mile","Average miles per gallon","Broker commission rate"], ans:1, exp:"Cost per mile is the foundation of all owner-operator profitability decisions. Without it you cannot evaluate any load offer, set minimum rates, or understand whether you are making or losing money." },
    ]},
    { id:"o3", title:"Load Boards and Rate Negotiation", icon:"📦", duration:"3 min read", xp:70, content:[
      { type:"intro", text:"The load board is your marketplace. How well you use it determines your income. The best owner-operators do not live on the spot market - they use it strategically while building direct relationships that pay better." },
      { type:"steps", title:"Load Board Mastery", items:[
        "DAT Power - Industry standard. Best for spot market data and lane rate benchmarking.",
        "Truckstop.com - Strong broker database. Good for relationship building.",
        "Rate Per Mile Target - Know your minimum before opening any load board.",
        "Counter Strategy - Always counter. First offer is never the best offer.",
        "Broker Credit Check - Check broker payment days (DAT or Truckstop). Avoid 45+ day payers.",
        "Building Direct Lanes - After 3 loads with a shipper, ask for a rate agreement directly.",
        "Factoring vs. Quick Pay - Factor at 2-5% or broker quick pay at 2-3% to manage cash flow.",
      ]},
      { type:"tip", text:"Never accept a load you cannot profit on just to keep moving. Empty miles cost you roughly your fuel burn plus wear and tear. A $1.90/mile load going the wrong direction is often worse than a 2-day layover positioning for a $2.50 lane." },
      { type:"quiz", q:"What should you check before working with a new freight broker?", opts:["Their website design","Their payment history and days to pay","Whether they use DAT or Truckstop","Their office location"], ans:1, exp:"Always check a broker's credit score and average days to pay on DAT or Truckstop before hauling a load. A broker who pays in 60+ days or has credit issues can devastate your cash flow." },
    ]},
    { id:"o4", title:"Insurance and Legal Protection", icon:"🛡️", duration:"3 min read", xp:85, content:[
      { type:"intro", text:"Insurance is your second-largest operating expense and your most important one. One uninsured incident can end your business permanently. Understand exactly what you have and what you do not have before you haul." },
      { type:"steps", title:"Required Insurance Coverage", items:[
        "Primary Liability - Minimum $750K required by FMCSA. Most brokers require $1M.",
        "Physical Damage - Covers your truck. Required if you have a lender.",
        "Cargo Insurance - Usually $100K minimum. Check shipper requirements before booking.",
        "Bobtail/Non-Trucking Liability - Covers you when operating without a trailer.",
        "Occupational Accident - Acts like workers comp for independent owner-operators.",
        "Umbrella Policy - $1-2M additional coverage. Smart for high-value freight lanes.",
        "New Authority Budget - Expect $1,000-1,500/month year one. Drops after 2 clean years.",
      ]},
      { type:"tip", text:"Read your policy. Do not assume you are covered. I know drivers who thought they had cargo coverage and found out at 2am during a load dispute that they did not. Know your deductibles, your exclusions, and your claims process before you need it." },
      { type:"quiz", q:"What is the FMCSA minimum liability insurance for a dry van carrier?", opts:["$100,000","$500,000","$750,000","$1,000,000"], ans:2, exp:"FMCSA requires a minimum of $750,000 in public liability insurance for property carriers. However, most freight brokers require $1,000,000 minimum before they will book you a load." },
    ]},
    { id:"o5", title:"Taxes and Business Finance", icon:"📊", duration:"14 min read", xp:95, content:[
      { type:"intro", text:"Self-employment taxes will shock you if you are unprepared. As an owner-operator you owe both the employee and employer portions of Social Security and Medicare - 15.3% on top of income tax. Plan for this from day one." },
      { type:"steps", title:"Owner-Operator Tax Essentials", items:[
        "Set Aside 25-30% - Put this in a separate account every week. Non-negotiable.",
        "Quarterly Estimated Taxes - Due January, April, June, September. Late = penalties.",
        "Deductible Expenses - Fuel, tolls, maintenance, insurance, phone, per diem meals.",
        "Per Diem Deduction - $69/day away from home tax-free. Track every overnight.",
        "Depreciation - Section 179 allows immediate expensing of truck purchase in many cases.",
        "Hire a Trucking CPA - Worth $500-1,500/year. They save you 5-10x that in taxes.",
        "Bookkeeping - Use QuickBooks Self-Employed. Reconcile weekly, not at tax time.",
      ]},
      { type:"tip", text:"I saved a driver from a $42,000 tax bill by teaching him to track per diem and fuel expenses properly. The tax code has real advantages for owner-operators. But you have to document everything or those deductions disappear at audit." },
      { type:"quiz", q:"What percentage should an owner-operator set aside for taxes?", opts:["10-15%","15-20%","25-30%","35-40%"], ans:2, exp:"Owner-operators pay self-employment tax (15.3%) plus federal and state income tax. Setting aside 25-30% of net income each week ensures you have enough for quarterly estimates and year-end tax liability." },
    ]},
    { id:"o6", title:"Finding Your First Load", icon:"🎯", duration:"4 min read", xp:85, content:[
      { type:"intro", text:"Your first load as an owner-operator is the hardest one. You have no track record, no broker relationships, and you are competing against experienced operators. Here is exactly how to get moving without getting burned." },
      { type:"steps", title:"Where to Find Loads", items:[
        "DAT Load Board - largest in the industry, 400M+ loads per year. Start here.",
        "Truckstop.com - second largest, strong on certain lanes.",
        "Direct shippers - harder to get but pay 20-30% more than broker loads.",
        "Dispatching services - they find loads for you for 5-10% of gross. Worth it when starting.",
        "Freight matching apps - Convoy, Uber Freight, Amazon Freight for newer operators."
      ]},
      { type:"steps", title:"First 90 Days Strategy", items:[
        "1. Accept slightly lower rates at first to build a rating history on load boards.",
        "2. Never haul under your cost per mile - know your number before accepting anything.",
        "3. Always get the rate confirmation in writing before moving.",
        "4. Check broker credit scores on DAT before hauling for any new broker.",
        "5. Document every load - BOL, rate confirmation, proof of delivery.",
        "6. Follow up on payment within 30 days - do not let receivables age."
      ]},
      { type:"tip", title:"Big Earl Says", text:"The broker is not your friend and not your enemy. They are a business. They will offer you the lowest rate they think you will accept. Counter every single time. Even if you get turned down 9 times, that 10th counter that sticks puts real money in your pocket." },
      { type:"quiz", questions:[
        { q:"What is the largest load board in the trucking industry?", opts:["Truckstop.com","Convoy","DAT Load Board","Amazon Freight"], ans:2, exp:"DAT Load Board is the largest with over 400 million loads posted annually. Most brokers post there first." },
        { q:"Before hauling for a new broker, you should check their:", opts:["Website design","Credit score on DAT","Number of social media followers","Office location"], ans:1, exp:"Always check broker credit scores on DAT before hauling. Slow-pay or no-pay brokers are flagged with ratings and warnings from other carriers." },
        { q:"A dispatching service typically charges:", opts:["1-2% of gross","5-10% of gross","15-20% of gross","Flat fee per load"], ans:1, exp:"Dispatching services charge 5-10% of gross revenue. Worth it for new operators who don't yet have broker relationships." },
        { q:"When receiving a rate confirmation, you should:", opts:["Ignore it and rely on verbal agreement","Sign it and move immediately","Review all terms before signing","Only check the total amount"], ans:2, exp:"Review every detail: rate, pickup/delivery windows, detention terms, fuel surcharge, and accessorial charges before signing." },
      ]},
    ]},
    { id:"o7", title:"Fuel Management and IFTA", icon:"⛽", duration:"5 min read", xp:90, content:[
      { type:"intro", text:"IFTA is one of the most confusing parts of running your own authority. Get it wrong and you owe penalties and interest. Get it right and you may actually get a refund check every quarter." },
      { type:"steps", title:"How IFTA Works", items:[
        "You pay fuel tax at the pump in every state you buy fuel.",
        "You owe fuel tax in every state you drive through based on miles driven there.",
        "IFTA reconciles the difference - overpaid means refund, underpaid means you owe.",
        "File quarterly: January 31, April 30, July 31, October 31.",
        "Register in your base state BEFORE crossing state lines."
      ]},
      { type:"steps", title:"IFTA Record Keeping", items:[
        "Keep ALL fuel receipts - every gallon in every state must be documented.",
        "Track miles by state - your ELD does this automatically.",
        "Maintain trip records for 4 years - IFTA audits look back 4 years.",
        "Use trucking software like TruckLogics or Rigbooks to automate calculations.",
        "Fuel in low-tax states when you can plan it - Texas and New Jersey beat California."
      ]},
      { type:"tip", title:"Big Earl Says", text:"Smart fueling can save you $200-400 on a single national run. Over a year that is $10,000-20,000 in your pocket instead of the pump. Know your route, know the fuel prices, and plan your fill-ups like you plan your miles." },
      { type:"quiz", questions:[
        { q:"IFTA quarterly filing deadlines are:", opts:["Jan 1, Apr 1, Jul 1, Oct 1","Jan 31, Apr 30, Jul 31, Oct 31","Mar 15, Jun 15, Sep 15, Dec 15","Monthly"], ans:1, exp:"IFTA is filed quarterly: January 31, April 30, July 31, and October 31 for the previous quarter." },
        { q:"IFTA audit records must be kept for:", opts:["1 year","2 years","4 years","7 years"], ans:2, exp:"Maintain all trip records, fuel receipts, and IFTA filings for 4 years. IFTA audits can look back that far." },
        { q:"When you pay more fuel tax than you owe across all states:", opts:["You pay a penalty","Nothing happens","You receive a refund","You must refile"], ans:2, exp:"If you paid more at the pump than you owe based on miles driven, IFTA sends you a refund check for the difference." },
        { q:"Before crossing state lines, you must:", opts:["Call FMCSA","Register for IFTA in your base state first","Pay all states upfront","Only file at year end"], ans:1, exp:"You must register with your base state's IFTA program before operating across state lines. Operating without registration is a violation." },
      ]},
    ]},
    { id:"o8", title:"Building Shipper Relationships", icon:"🤝", duration:"4 min read", xp:80, content:[
      { type:"intro", text:"Every load board load costs you broker fees. Every direct shipper relationship you build puts that broker margin directly in your pocket. One shipper who gives you 3 loads a week at direct rates is worth more than 50 broker relationships." },
      { type:"steps", title:"How to Find Direct Shippers", items:[
        "Drive by industrial parks near your home base and note company names.",
        "Look at load board loads - note which companies ship repeatedly on your lanes.",
        "LinkedIn - search for logistics managers and supply chain directors at manufacturers.",
        "Cold calls - call the shipping department directly, not customer service.",
        "Start with one lane and one shipper - prove yourself before asking for more."
      ]},
      { type:"steps", title:"Your Direct Shipper Pitch", items:[
        "Lead with reliability - shippers care about on-time delivery more than price.",
        "Offer dedicated capacity - tell them you hold space for them every week.",
        "Price below what brokers charge - you can go lower because there is no middleman.",
        "Provide references - even one professional reference accelerates trust.",
        "Document your on-time rate and present it as your track record."
      ]},
      { type:"tip", title:"Big Earl Says", text:"I built my business on 3 shippers. Three companies that trusted me to show up every week. They paid me direct, I charged less than the broker did, and everybody won. That is the business model. Chase direct freight from day one." },
      { type:"quiz", questions:[
        { q:"What do direct shippers pay compared to broker loads?", opts:["Less than brokers","About the same","20-30% more","Twice as much"], ans:2, exp:"Direct shipper relationships typically pay 20-30% more because there is no broker taking a margin in the middle." },
        { q:"When pitching a direct shipper, your strongest argument is:", opts:["Your truck is new","You have the lowest rates","Reliability and dedicated capacity","You have a CDL"], ans:2, exp:"Shippers care most about reliability. Lead with on-time delivery record and the promise of dedicated capacity every week." },
        { q:"The best place to find direct shippers in your area is:", opts:["Load boards only","Driving by industrial parks and noting company names","Social media ads","Truck stops"], ans:1, exp:"Industrial parks, warehouses, and manufacturing districts near your home base are gold mines for direct shipper relationships." },
        { q:"How many direct shippers do you need to build a sustainable business?", opts:["50+","20-30","As few as 3-5 consistent ones","At least 100"], ans:2, exp:"Even 3-5 reliable direct shippers giving consistent weekly freight can build a highly profitable and sustainable operation." },
      ]},
    ]},
    { id:"o9", title:"Truck Maintenance Planning", icon:"🔧", duration:"5 min read", xp:85, content:[
      { type:"intro", text:"Your truck is your business. A breakdown on the road costs you in four ways: repairs, towing, lost revenue, and late delivery penalties. The operators who stay profitable maintain aggressively and never defer critical repairs." },
      { type:"steps", title:"Preventive Maintenance Schedule", items:[
        "Every 15,000 miles - Oil and filter change (check spec for synthetic intervals).",
        "Every 25,000 miles - Fuel filters, air filters, brake adjustment check.",
        "Every 50,000 miles - Coolant flush, transmission fluid, DPF cleaning.",
        "Every 100,000 miles - Clutch inspection, turbo inspection, injector service.",
        "Annually - Full brake inspection, wheel bearing repack, fifth wheel inspection."
      ]},
      { type:"steps", title:"Building Your Maintenance Fund", items:[
        "Set aside $0.15-0.20 per mile specifically for maintenance and repairs.",
        "On 100,000 miles per year that is $15,000-20,000 - which is about right.",
        "Never touch this fund for personal expenses - it is not income.",
        "Keep 3 months of truck payments in a separate emergency reserve.",
        "Build relationships with 2-3 reliable shops in your most common lanes."
      ]},
      { type:"tip", title:"Big Earl Says", text:"A $50 belt that snaps on I-80 in Wyoming becomes a $3,000 tow, a $500 repair, and two days of lost revenue. Inspect your truck every single day like your business depends on it - because it does." },
      { type:"quiz", questions:[
        { q:"How much should you set aside per mile for maintenance?", opts:["$0.05-0.10","$0.15-0.20","$0.30-0.40","$0.50+"], ans:1, exp:"Set aside $0.15-0.20 per mile for maintenance. At 100,000 miles/year that is $15,000-20,000 which is realistic for a well-maintained truck." },
        { q:"Oil changes on most modern diesel trucks should occur every:", opts:["5,000 miles","10,000 miles","15,000 miles","25,000 miles"], ans:2, exp:"Most modern diesel trucks use synthetic oil with intervals of approximately 15,000 miles. Check your manufacturer specifications." },
        { q:"DPF cleaning is typically needed every:", opts:["15,000 miles","25,000 miles","50,000 miles","100,000 miles"], ans:2, exp:"Diesel Particulate Filter cleaning is typically needed every 50,000 miles to maintain engine performance and fuel efficiency." },
        { q:"Your maintenance fund should NEVER be used for:", opts:["Tires","Brake work","Personal expenses","Engine repairs"], ans:2, exp:"The maintenance fund is strictly for the truck. Using it for personal expenses leaves you unable to pay for critical repairs when they happen." },
      ]},
    ]},
    { id:"o10", title:"Scaling to a Small Fleet", icon:"🚛", duration:"5 min read", xp:95, content:[
      { type:"intro", text:"Going from 1 truck to 2 trucks is not twice the income - it is twice the complexity. Most owner-operators who try to scale too fast fail because they underestimate the management burden. Here is how the successful ones do it." },
      { type:"steps", title:"Signs You Are Ready to Scale", items:[
        "Profitable for at least 12 consecutive months.",
        "3 months of operating expenses in reserve.",
        "More freight than your one truck can handle consistently.",
        "A trusted driver candidate or a proven hiring process.",
        "Bookkeeping, dispatch, and compliance systems are already working."
      ]},
      { type:"steps", title:"Hiring Your First Driver", items:[
        "MVR check - pull their motor vehicle record before any interview.",
        "PSP report - Pre-employment Screening Program shows crash and inspection history.",
        "Drug and alcohol clearinghouse - federal requirement before hiring any CDL driver.",
        "Verify CDL and medical certificate directly with the state - not from the driver.",
        "90-day probation with ride-along monitoring before full independence."
      ]},
      { type:"tip", title:"Big Earl Says", text:"The number one mistake I see is hiring fast because you need someone now. A bad driver costs you more than an empty truck. Your name is on that authority and you are liable for what they do. Take 30 days to find the right person. Check everything." },
      { type:"quiz", questions:[
        { q:"Before scaling to a second truck, you should have at minimum:", opts:["1 month of reserves","3 months of operating expenses in reserve","6 months of profit","A second CDL"], ans:1, exp:"3 months of operating expenses in reserve is the minimum safety net before adding overhead with a second truck." },
        { q:"A PSP report shows a driver's:", opts:["Credit history","Criminal record","Crash and inspection history from FMCSA","Social security number"], ans:2, exp:"The Pre-employment Screening Program report shows crashes and roadside inspection violations on file with FMCSA - essential before any hire." },
        { q:"The Drug and Alcohol Clearinghouse check is:", opts:["Optional for small carriers","A federal requirement before hiring any CDL driver","Only for hazmat drivers","Only needed every 3 years"], ans:1, exp:"Querying the FMCSA Drug and Alcohol Clearinghouse is a federal requirement before hiring any CDL driver, regardless of carrier size." },
        { q:"An empty truck is better than a bad driver because:", opts:["It burns less fuel","Your authority and liability follow their actions","It looks better for CSA","Trucks don't need maintenance when parked"], ans:1, exp:"As the carrier, you are liable for what your drivers do under your authority. One bad hire can end your business through accidents, violations, and lawsuits." },
      ]},
    ]},
    { id:"o11", title:"Taxes and Deductions", icon:"💰", duration:"5 min read", xp:90, content:[
      { type:"intro", text:"Owner-operators who do not understand their taxes overpay by thousands every year. The IRS gives truck owners significant deductions - but you have to know what they are, document them properly, and pay quarterly or face penalties." },
      { type:"steps", title:"Top Tax Deductions for Truckers", items:[
        "Per diem - $69/day for every day away from home. Largest single deduction.",
        "Fuel - 100% deductible. Save every receipt.",
        "Truck loan interest and depreciation - fully deductible business expenses.",
        "All insurance premiums - truck, cargo, liability, health.",
        "ELD subscription, load board fees, dispatching fees - all deductible.",
        "Cell phone business portion - typically 80-90% for full-time truckers.",
        "Repairs and maintenance - all costs directly related to the truck."
      ]},
      { type:"steps", title:"Quarterly Tax Payments", items:[
        "Self-employed pay 15.3% self-employment tax plus income tax.",
        "Pay quarterly: April 15, June 15, September 15, January 15.",
        "Underpay quarterly and you face penalties even if you pay in full at year end.",
        "Set aside 25-30% of every payment into a dedicated tax account.",
        "Use ATBS or a trucking-specific accountant - they know our deductions."
      ]},
      { type:"tip", title:"Big Earl Says", text:"The per diem alone saves you $5,000-8,000 in taxes every year. Most drivers I talk to do not even know what it is. Talk to a trucking accountant not a general one. They will save you their fee many times over." },
      { type:"quiz", questions:[
        { q:"The per diem deduction for truckers is approximately:", opts:["$35/day","$50/day","$69/day","$100/day"], ans:2, exp:"The IRS per diem rate for transportation workers is $69 per day for days away from home - one of the largest available deductions." },
        { q:"Self-employment tax for owner-operators is:", opts:["7.65%","10%","15.3%","20%"], ans:2, exp:"Self-employed individuals pay 15.3% self-employment tax (Social Security + Medicare) because there is no employer sharing the cost." },
        { q:"Quarterly estimated taxes are due:", opts:["Jan, Mar, Jun, Sep","Apr, Jun, Sep, Jan","Monthly","Only at year end"], ans:1, exp:"Quarterly payments are due April 15, June 15, September 15, and January 15. Missing them results in penalties even if you pay in full at year end." },
        { q:"What percentage of gross revenue should owner-operators set aside for taxes?", opts:["10-15%","20-25%","25-30%","35-40%"], ans:2, exp:"Set aside 25-30% of every payment received. This covers self-employment tax plus federal and state income tax at most income levels." },
      ]},
    ]},
    { id:"o12", title:"Building Your Brand and Reputation", icon:"⭐", duration:"4 min read", xp:80, content:[
      { type:"intro", text:"Your reputation is your business. Shippers choose carriers based on reliability. Brokers offer best loads to drivers they trust. Your CSA score, on-time percentage, and how you handle problems define your value in this industry." },
      { type:"steps", title:"Your CSA Score", items:[
        "CSA scores every carrier publicly at safer.fmcsa.dot.gov.",
        "7 categories scored: Unsafe Driving, HOS, Driver Fitness, Substances, Maintenance, Hazmat, Crash.",
        "High scores trigger FMCSA interventions and loss of shipper contracts.",
        "Low scores qualify you for safety bonuses and premium shipper lanes.",
        "Check your score monthly - know where you stand before a shipper checks you."
      ]},
      { type:"steps", title:"Building a Professional Brand", items:[
        "Keep equipment clean and lettered - your truck is a moving billboard.",
        "Respond to all communications within 2 hours during business hours.",
        "Call before you are late - shippers hear from you first, not last.",
        "Get verified on DAT and Truckstop.com - verification builds instant credibility.",
        "Ask satisfied shippers for written references - one good reference opens 10 doors."
      ]},
      { type:"tip", title:"Big Earl Says", text:"I built 28 years of reputation one delivery at a time. Every on-time delivery, every proactive call, every problem handled professionally - that was a deposit in the reputation bank. It compounds. Twenty years of that and I never had to look for work. The work found me." },
      { type:"quiz", questions:[
        { q:"Your CSA score is publicly available at:", opts:["truckscore.com","safer.fmcsa.dot.gov","cdl.gov","fmcsa.dot.gov/register"], ans:1, exp:"Check your score at safer.fmcsa.dot.gov. Shippers and brokers check this before awarding contracts. Know your score before they do." },
        { q:"A high CSA score means:", opts:["Excellent safety record","More premium loads offered","Risk of FMCSA interventions and lost contracts","Lower insurance rates"], ans:2, exp:"Higher CSA scores (worse performance) trigger FMCSA compliance reviews, investigations, and can cause shippers to drop your carrier." },
        { q:"How many CSA categories are tracked by FMCSA?", opts:["3","5","7","10"], ans:2, exp:"Seven BASICS are tracked: Unsafe Driving, HOS Compliance, Driver Fitness, Controlled Substances, Vehicle Maintenance, Hazmat, and Crash Indicator." },
        { q:"The most effective way to build shipper trust is:", opts:["Lowest rates in the market","Consistent on-time delivery and proactive communication","Newest equipment","Most loads per week"], ans:1, exp:"Reliability and communication build lasting shipper relationships. Shippers will pay more for a carrier they trust to show up and communicate." },
      ]},
    ]},
  ],
};

// ─── 50+ CDL QUESTIONS ────────────────────────────────────────────────────────
const CDL_Q = {
  general:[
    { q:"What is the maximum legal weight for most interstate highways?", opts:["60,000 lbs","70,000 lbs","80,000 lbs","90,000 lbs"], ans:2, exp:"The federal maximum gross vehicle weight on interstate highways is 80,000 lbs. Individual axle limits also apply: 20,000 lbs per single axle, 34,000 lbs per tandem axle group.", cat:"general" },
    { q:"What does GVWR stand for?", opts:["Gross Vehicle Weight Rating","Gross Vehicle Weight Requirement","General Vehicle Weight Restriction","Gross Volume Weight Ratio"], ans:0, exp:"GVWR is the Gross Vehicle Weight Rating - the maximum weight the vehicle is designed to safely carry including the vehicle itself, cargo, fuel, and passengers.", cat:"general" },
    { q:"When must you stop at a railroad crossing?", opts:["Only if the lights are flashing","If you are hauling hazmat or transporting passengers","Only if a train is visible","Always stop at all crossings"], ans:1, exp:"CMV drivers must always stop before railroad crossings if they are transporting hazardous materials or passengers, regardless of whether a train is present.", cat:"general" },
    { q:"How far ahead should you look on a highway?", opts:["5-8 seconds","10-12 seconds","12-15 seconds","20-25 seconds"], ans:2, exp:"The FMCSA recommends looking 12-15 seconds ahead on highways - approximately a quarter mile at 60 mph. This gives you time to respond to hazards before they become emergencies.", cat:"general" },
    { q:"What is the minimum following distance at highway speed?", opts:["3 seconds","5 seconds","7 seconds","9 seconds"], ans:2, exp:"Minimum 7 seconds of following distance at highway speed. Add one second for every 10 feet of vehicle length over 40 feet. Double this in rain or fog.", cat:"general" },
    { q:"When should hazard lights be used while driving?", opts:["In rain or fog","When driving slowly","When legally parked and creating a hazard","At any time the driver feels unsafe"], ans:2, exp:"Hazard lights should only be used when the vehicle is legally stopped and creating a safety hazard. Using them while moving can confuse other drivers about your intentions.", cat:"general" },
    { q:"What action is prohibited under federal law while operating a CMV?", opts:["Eating while driving","Using a hand-held mobile phone","Listening to the radio","Drinking coffee"], ans:1, exp:"Federal law (49 CFR 392.82) prohibits CMV drivers from using hand-held mobile devices while operating a commercial vehicle. Violations can result in fines up to $2,750.", cat:"general" },
    { q:"What is the correct way to handle a tire blowout?", opts:["Brake hard immediately","Grip the wheel, accelerate slightly to stabilize, then decelerate gradually","Pull over immediately by braking hard","Turn into the blowout direction"], ans:1, exp:"During a blowout, maintain or slightly increase throttle to stabilize the vehicle, grip the steering wheel firmly, counter-steer as needed, then gradually reduce speed and pull to the shoulder.", cat:"general" },
    { q:"What does a yellow diamond-shaped sign indicate?", opts:["Construction zone","Warning or advisory information","Regulatory requirement","Service area ahead"], ans:1, exp:"Yellow diamond-shaped signs are warning signs that alert drivers to potential hazards ahead such as curves, hills, intersections, or unusual road conditions.", cat:"general" },
    { q:"What is the correct stopping procedure at a stop sign?", opts:["Slow and proceed if clear","Stop completely at the stop line, check all directions, then proceed","Stop only if other traffic is present","Slow to 5 mph and yield"], ans:1, exp:"At a stop sign you must make a complete stop at the stop line or before the crosswalk. Check all directions for traffic and pedestrians before proceeding.", cat:"general" },
    { q:"When must you use a seatbelt in a CMV?", opts:["Only on highways","Only when carrying passengers","At all times when operating the vehicle","Only when required by employer policy"], ans:2, exp:"Federal regulations require CMV operators to wear seatbelts at all times when operating the vehicle. Passengers in the cab must also be buckled.", cat:"general" },
    { q:"How should you manage speed on a steep downgrade?", opts:["Use service brakes continuously","Coast in neutral to save fuel","Select proper gear before descent and use engine braking","Increase speed then brake at the bottom"], ans:2, exp:"Always select the proper lower gear before beginning a descent and use engine braking (exhaust brake/jake brake) to maintain safe speed. Service brakes on steep grades cause fade and potential brake failure.", cat:"general" },
  ],
  airbrakes:[
    { q:"What is the normal operating pressure range for air brakes?", opts:["50-75 psi","100-125 psi","150-175 psi","200-225 psi"], ans:1, exp:"Normal operating air pressure for truck air brakes is 100-125 psi. The governor cuts out air compressor at approximately 125 psi and cuts back in at approximately 100 psi.", cat:"airbrakes" },
    { q:"At what pressure does the low air warning device activate?", opts:["90 psi","75 psi","60 psi","45 psi"], ans:2, exp:"The low air pressure warning device must activate at 60 psi or higher. At this point you must immediately find a safe place to stop.", cat:"airbrakes" },
    { q:"What happens to spring brakes when air pressure drops below 20-45 psi?", opts:["Nothing, they release","They apply automatically","They release completely","Air brakes fail silently"], ans:1, exp:"Spring brakes are designed to apply automatically when air pressure drops to 20-45 psi. This is a safety failsafe - the truck will stop itself if air pressure is lost.", cat:"airbrakes" },
    { q:"What is brake fade?", opts:["Gradual brake adjustment over time","Loss of braking effectiveness due to heat buildup","Air pressure equalizing between chambers","Normal wear on brake linings"], ans:1, exp:"Brake fade is the loss of braking effectiveness caused by excessive heat buildup in the brake linings. It occurs when service brakes are applied continuously on downgrades instead of using engine braking.", cat:"airbrakes" },
    { q:"How do you perform a static air leak test?", opts:["Apply brakes and check gauge drops","Build to normal pressure, shut off engine, check drop rate","Open drain valves and check flow","Apply maximum brake force and hold for 30 seconds"], ans:1, exp:"For a static air leak test: build pressure to governor cutout, shut off engine, wait one minute. Acceptable leakage is no more than 2 psi for single vehicles, 3 psi for combination vehicles.", cat:"airbrakes" },
    { q:"What is the purpose of the air dryer on an air brake system?", opts:["Increases air pressure","Removes moisture and contaminants from compressed air","Cools the air compressor","Regulates brake application force"], ans:1, exp:"The air dryer removes moisture and oil from the compressed air before it enters the air tanks. Moisture in air tanks causes corrosion and can freeze in cold weather, potentially disabling brakes.", cat:"airbrakes" },
    { q:"What does the emergency (red) glad hand connect to?", opts:["Service brake circuit","Emergency/supply circuit","Trailer ABS system","Parking brake release"], ans:1, exp:"The red glad hand connects to the emergency supply line. It provides air to charge the trailer's emergency reservoir and release the trailer spring brakes.", cat:"airbrakes" },
    { q:"How do you check if the trailer brakes are connected and working?", opts:["Drive forward slowly and brake","Pull forward slightly against locked trailer brakes","Check the air gauge only","Listen for air escaping at the connection"], ans:1, exp:"After connecting the trailer, pump up air pressure, release the tractor parking brake, and gently pull forward against the applied trailer brakes. Resistance confirms trailer brakes are connected and working.", cat:"airbrakes" },
    { q:"What is required before driving after the air pressure warning light comes on?", opts:["Drive slowly to a truck stop","Find a safe place to stop immediately","Call dispatch first","Drive until pressure builds back up"], ans:1, exp:"When the low air pressure warning activates at 60 psi you must find a safe place to stop immediately. At 20-45 psi spring brakes will apply automatically regardless of driver action.", cat:"airbrakes" },
    { q:"How often should air brake systems be inspected under FMCSA?", opts:["Annually only","As part of every pre-trip inspection","Every 30,000 miles","Only when problems arise"], ans:1, exp:"Air brake system components must be inspected as part of every pre-trip inspection. This includes checking air pressure buildup rate, listening for leaks, and checking brake stroke adjustment.", cat:"airbrakes" },
  ],
  combination:[
    { q:"What is the maximum overall length for a combination vehicle on most interstates?", opts:["53 feet","65 feet","75 feet","80 feet"], ans:2, exp:"Most states allow combination vehicles up to 75 feet in total length on interstate highways. Some western states allow longer configurations (LCV routes) with special permits.", cat:"combination" },
    { q:"What causes trailer sway?", opts:["Driving too slowly","Weight distributed too far forward","Improper loading with too much weight at rear, or crosswinds","Using cruise control"], ans:2, exp:"Trailer sway is primarily caused by loading too much weight at the rear of the trailer shifting the center of gravity, or by crosswinds at highway speed. Smooth steering inputs help prevent and correct it.", cat:"combination" },
    { q:"How do you correct trailer sway when it begins?", opts:["Brake hard to slow down","Accelerate to straighten the trailer","Avoid braking, ease off throttle, steer in the direction of sway","Turn sharply in the opposite direction"], ans:2, exp:"When trailer sway begins, avoid braking (it makes sway worse), ease off the throttle, and counter-steer smoothly in the direction of the sway. If equipped, manual trailer brake application can help.", cat:"combination" },
    { q:"What is the maximum kingpin setback from the front of the trailer?", opts:["34 inches","36 inches","40 inches","46 inches"], ans:0, exp:"The standard kingpin setback is 34 inches from the front face of the trailer. This positioning optimizes weight distribution across axles and affects how much weight is on the steer axles.", cat:"combination" },
    { q:"After coupling, how do you verify the fifth wheel is properly locked?", opts:["Check visually that the pin is closed","Pull forward hard against the brakes","Perform a tug test by pulling against locked trailer brakes","All of the above"], ans:3, exp:"Proper fifth wheel coupling verification requires: visual inspection to confirm the locking jaw is closed around the kingpin, checking that no light is visible between tractor and trailer, and performing a tug test pulling forward with trailer brakes applied.", cat:"combination" },
    { q:"What is rearward amplification in combination vehicles?", opts:["Echo from the trailer body","The tendency for rear trailer wheels to move more than front wheels during evasive maneuvers","Amplified braking force at the rear","Increased turning radius"], ans:1, exp:"Rearward amplification is the tendency for the rear of a trailer to whip side-to-side more than the front during sudden steering maneuvers. A 2-axle trailer can amplify movement up to 2x; a B-train up to 3.5x.", cat:"combination" },
    { q:"What does sliding the tandems forward do to axle weights?", opts:["Reduces drive axle weight, increases trailer axle weight","Reduces trailer axle weight, increases drive axle weight","Has no effect on individual axle weights","Reduces steer axle weight"], ans:0, exp:"Sliding the trailer tandems forward shifts weight toward the rear of the tractor, reducing the load on the trailer rear axles and increasing it on the drive axles. Sliding back does the opposite.", cat:"combination" },
    { q:"When should you downshift while pulling a heavy load on a downgrade?", opts:["At the bottom of the grade","Halfway down","Before you begin the descent","When speed increases beyond safe level"], ans:2, exp:"Always select the correct lower gear before starting a descent. If you wait until you are on the grade you may not be able to shift safely due to speed. There is an old saying: if in doubt, do not go out - on a downgrade.", cat:"combination" },
    { q:"What is the correct sequence for uncoupling a semi-trailer?", opts:["Remove glad hands, lower landing gear, release fifth wheel","Lower landing gear, disconnect glad hands, release fifth wheel","Chock trailer wheels, lower landing gear, disconnect air lines, release fifth wheel","Release fifth wheel, then lower landing gear"], ans:2, exp:"Correct uncoupling sequence: apply trailer brakes, chock trailer wheels, lower landing gear to contact ground, disconnect electrical and air lines, unlock fifth wheel jaw, and then pull tractor forward slowly.", cat:"combination" },
  ],
  roadsigns:[
    { q:"What shape and color is a warning sign?", opts:["Red octagon","Yellow diamond","White rectangle","Orange diamond"], ans:1, exp:"Warning signs are yellow diamond-shaped. They alert drivers to potential hazards ahead such as curves, hills, animal crossings, and lane reductions.", cat:"roadsigns" },
    { q:"What does a pennant-shaped sign indicate?", opts:["Curve ahead","Begin passing zone","No passing zone","End of construction"], ans:2, exp:"A pennant-shaped (triangular) sign is used exclusively to mark the beginning of a No Passing Zone. It is always placed on the left side of the road.", cat:"roadsigns" },
    { q:"A flashing red light at an intersection means:", opts:["Slow and proceed","Yield to cross traffic","Stop completely then proceed when safe","Road closed ahead"], ans:2, exp:"A flashing red signal is treated the same as a stop sign. Come to a complete stop, check all traffic and pedestrians, and proceed when safe.", cat:"roadsigns" },
    { q:"What does an orange sign indicate?", opts:["Regulatory requirement","Service area","Construction or work zone","Recreational area"], ans:2, exp:"Orange signs indicate construction, maintenance, or utility work zones. Speed limits in these zones are legally enforceable and fines are often doubled.", cat:"roadsigns" },
    { q:"What does a green sign typically indicate?", opts:["Warning of hazard ahead","Directional and distance information","Regulatory requirement","Service facilities"], ans:1, exp:"Green signs provide directional guidance and distance information including highway route numbers, exit numbers, and distance to cities and destinations.", cat:"roadsigns" },
    { q:"What does a white rectangular sign indicate?", opts:["Advisory speed","Warning of hazard","Regulatory requirement (must obey)","General information"], ans:2, exp:"White rectangular signs are regulatory signs that indicate laws and rules that must be obeyed, such as speed limits, do not enter, one way, and no turn signs.", cat:"roadsigns" },
    { q:"What does a blue sign along a highway indicate?", opts:["Rest areas only","Emergency services only","Motorist services like food, fuel, and lodging","State information centers"], ans:2, exp:"Blue signs indicate motorist services including food, fuel, lodging, hospital, and other traveler amenities at upcoming exits.", cat:"roadsigns" },
    { q:"What does a sign with a red circle and slash over a symbol mean?", opts:["Caution required","The indicated action is prohibited","Advisory only","Historical marker"], ans:1, exp:"A red circle with a diagonal slash over a symbol is an international prohibition sign meaning the indicated action is not allowed. Examples include no trucks, no U-turn, and no passing.", cat:"roadsigns" },
    { q:"What does a yield sign require?", opts:["Full stop always","Slow to 15 mph","Slow down and stop if necessary to let cross traffic pass","Match speed of oncoming traffic"], ans:2, exp:"A yield sign requires you to slow down and be prepared to stop if necessary to allow cross traffic or pedestrians the right of way. You do not have to stop if the way is clear.", cat:"roadsigns" },
    { q:"What color and shape is a railroad crossing advance warning sign?", opts:["Yellow circle","Orange diamond","Yellow diamond with X","White with railroad symbol"], ans:0, exp:"The advance railroad crossing warning sign is yellow, round, with a black X and RR symbol. It warns of a railroad crossing ahead, usually 100 to 500 feet in advance.", cat:"roadsigns" },
    { q:"What does a double yellow center line mean?", opts:["Passing allowed in both directions","No passing in either direction","Passing allowed only when dashed","Two-way traffic begins"], ans:1, exp:"Double solid yellow center lines prohibit passing in both directions. Neither driver may cross the lines to pass.", cat:"roadsigns" },
  ],
  hazmat:[
    { q:"What does a placard on a vehicle indicate?", opts:["Oversized load","Hazardous materials being transported","Commercial vehicle with special permit","Temperature-controlled cargo"], ans:1, exp:"Placards on vehicles indicate that hazardous materials are being transported. They identify the class of hazmat and are required by DOT regulations when transporting materials above certain quantity thresholds.", cat:"hazmat" },
    { q:"Who is responsible for providing correct hazmat shipping papers?", opts:["The carrier","The driver","The shipper","FMCSA"], ans:2, exp:"The shipper is responsible for providing accurate shipping papers (manifest) and affixing proper labels to hazmat packages. The carrier and driver are responsible for refusing shipments that do not comply.", cat:"hazmat" },
    { q:"Where must hazmat shipping papers be kept while driving?", opts:["In the glove box","In a pouch on the door or in reach of the driver","In the trailer with the cargo","Faxed to dispatch"], ans:1, exp:"Hazmat shipping papers must be within the driver reach while driving or in a door pouch. If the driver is out of the vehicle, papers must be visible to emergency responders.", cat:"hazmat" },
    { q:"What is the minimum distance from a bridge a placarded vehicle must park?", opts:["100 feet","300 feet","500 feet","1,000 feet"], ans:1, exp:"Placarded hazmat vehicles must not be parked within 300 feet of bridges, tunnels, or buildings unless for essential operations like loading or fueling.", cat:"hazmat" },
  ],
};

// ─── 20+ SIMULATION SCENARIOS ─────────────────────────────────────────────────
const SIMS = [
  // EMERGENCY
  { id:"s1", track:"all", title:"Blown Steer Tire at Speed", icon:"💥", category:"Emergency", difficulty:"Expert",
    scenario:"You are southbound on I-35 at 67 mph with a full load. Without warning your right front steer tire blows. The truck violently pulls right. Traffic on your right. You have 2 seconds.",
    options:[
      { text:"Grip wheel hard and brake to a stop immediately", outcome:"bad", result:"Wrong Call", detail:"Hard braking during a front blowout causes violent pulling, possible jackknife, and loss of steering control. This is the most dangerous response possible.", lesson:"Never brake hard during a blowout. Grip and stabilize first." },
      { text:"Grip wheel, slight throttle to stabilize, then gradually slow", outcome:"good", result:"Textbook Response", detail:"A short burst of throttle during a blowout counteracts the drag of the flat tire and stabilizes the vehicle. Then ease off gradually, steer to the shoulder, and stop safely.", lesson:"Throttle briefly to stabilize, then slow and steer right." },
      { text:"Swerve left away from the flat tire pull", outcome:"bad", result:"Fatal Error", detail:"Swerving left at 67 mph into traffic is catastrophic. The physics of a blowout must be countered, not avoided by putting yourself into other vehicles.", lesson:"Steer to the shoulder. Never swerve into traffic." },
    ]},
  { id:"s2", track:"all", title:"Mountain Brake Fade", icon:"⛰️", category:"Emergency", difficulty:"Expert",
    scenario:"Westbound on I-70 descending Eisenhower Tunnel grade - 7% for 6 miles. Mile 3. Your service brakes are fading. Speed at 58 mph and climbing. A runaway truck ramp is 1.5 miles ahead.",
    options:[
      { text:"Keep applying service brakes harder to slow down", outcome:"bad", result:"Brake Failure Ahead", detail:"Continuing to ride service brakes on a fading system builds more heat. At this grade you have minutes before total brake failure - a runaway truck situation that kills people.", lesson:"Once brakes fade, service brakes are no longer your tool. Engine braking only." },
      { text:"Shift to neutral to reduce engine drag", outcome:"bad", result:"Catastrophically Wrong", detail:"Shifting to neutral removes all engine braking and allows the truck to accelerate freely down the grade. This is how trucks reach speeds of 80+ mph before impact.", lesson:"Never shift to neutral on a downgrade. Always use engine braking." },
      { text:"Use the runaway ramp - do not hesitate", outcome:"good", result:"Right Decision", detail:"Runaway truck ramps are designed exactly for this situation. They can stop a 40-ton truck from 60 mph safely. Using a ramp is not a failure - it is the correct professional decision.", lesson:"Use runaway ramps before losing control, not after." },
    ]},
  { id:"s3", track:"all", title:"Ice Bridge at 55 MPH", icon:"🌨️", category:"Emergency", difficulty:"Expert",
    scenario:"It is 29 degrees Fahrenheit on I-80 in Wyoming. You enter a bridge and instantly feel the trailer begin to push sideways. You are fully loaded at 78,000 lbs. No shoulder. Traffic behind.",
    options:[
      { text:"Brake hard to reduce speed immediately", outcome:"bad", result:"Jackknife Initiated", detail:"Hard braking on ice locks wheels, removes steering ability, and causes the trailer to continue forward while the tractor stops - a jackknife. At 78,000 lbs this is unsurvivable.", lesson:"Never brake hard on ice. Smooth inputs only." },
      { text:"Ease completely off throttle, steer straight, let friction slow you", outcome:"good", result:"Correct Technique", detail:"On ice, smooth is everything. Releasing throttle gradually reduces speed through engine braking without locking wheels. Straight steering maintains tracking. This is the only correct response.", lesson:"Ice requires feather-touch inputs. Smooth throttle release, straight steering." },
      { text:"Counter-steer sharply to correct the slide", outcome:"bad", result:"Overcorrection Crash", detail:"Sharp counter-steering on ice at 55 mph with a loaded trailer causes a snap-over reaction. The trailer overcorrects, the tractor follows, and you are off the road.", lesson:"On ice, never make sharp steering inputs. Gradually and smoothly." },
    ]},
  { id:"s4", track:"all", title:"Tire Fire in the Trailer", icon:"🔥", category:"Emergency", difficulty:"Intermediate",
    scenario:"You smell burning rubber. Your trailer brake temp light comes on. A car driver beside you on I-40 is gesturing at your rear tires. You are 6 miles from a truck stop.",
    options:[
      { text:"Drive the 6 miles to the truck stop quickly", outcome:"bad", result:"Fire Risk Escalated", detail:"A dragging brake or tire fire can reach 400+ degrees in minutes. Driving 6 miles means potentially arriving at the truck stop on fire. Cargo fires are catastrophic.", lesson:"Never drive to a destination with a potential tire or brake fire. Stop now." },
      { text:"Pull over immediately, inspect, do not open trailer doors", outcome:"good", result:"Correct Protocol", detail:"Pull off at the first safe spot, stay away from the wheel area, call 911 if you see flames. Do NOT open trailer doors - oxygen feeds fire. Let emergency services handle it.", lesson:"Stop, assess from a distance, call 911 if fire. Never open burning trailer." },
      { text:"Spray water on the tires from your water bottle", outcome:"bad", result:"Wrong Response", detail:"Water on a superheated brake drum can cause a steam explosion or crack the drum. Never put water on overheated brakes. Cool-down must happen naturally.", lesson:"Never put water on overheated brakes. Park and wait for cool-down." },
    ]},
  // COMPLIANCE
  { id:"s5", track:"all", title:"Weigh Station Overweight", icon:"⚖️", category:"Compliance", difficulty:"Intermediate",
    scenario:"Scales in Arkansas. Red light. Officer says your drive axles are 2,200 lbs over the 34,000 lb limit. The load was sealed at the shipper. You are 3 hours from delivery.",
    options:[
      { text:"Argue that the shipper sealed it and you cannot be responsible", outcome:"bad", result:"Wrong Approach", detail:"Once you signed the BOL and moved the load, you accepted responsibility. Officers have heard this argument thousands of times. Being argumentative risks a full inspection and more violations.", lesson:"You are responsible for your load's weight. Cooperate professionally." },
      { text:"Accept the citation, slide tandems to redistribute, continue legally", outcome:"good", result:"Professional Handling", detail:"Sliding tandems forward shifts weight from drive axles to trailer axles. If this brings you into compliance, you can legally continue. Document everything and notify dispatch.", lesson:"Sliding tandems is often the professional fix for axle weight issues." },
      { text:"Pay the fine and drive off without adjusting", outcome:"bad", result:"Legal Exposure Remains", detail:"If you cannot bring the truck into compliance by adjusting axles, you need an overweight permit or must wait for a partial offload. Paying a fine does not make an overweight truck legal to move.", lesson:"A fine does not make an overweight truck legal. Must achieve compliance to move." },
    ]},
  { id:"s6", track:"all", title:"HOS Close Call", icon:"⏰", category:"Compliance", difficulty:"Intermediate",
    scenario:"You have 1 hour and 10 minutes of drive time remaining. GPS shows 1 hour 45 minutes to your delivery. Dispatcher wants you to push through. It is 11 PM on a deserted interstate.",
    options:[
      { text:"Push through - it is only 35 minutes over on a deserted road", outcome:"bad", result:"Federal Violation", detail:"Running out of hours is a federal HOS violation regardless of road conditions, time of night, or dispatch pressure. Fines reach $16,000 per violation. Your CDL and your job are at risk.", lesson:"No schedule justifies an HOS violation. Your CDL is your livelihood." },
      { text:"Stop at the next legal parking spot, take your 10-hour break", outcome:"good", result:"Correct and Professional", detail:"Finding legal parking and stopping is always the right answer. Call dispatch with your location and ETA after break. Most receivers would rather have a safe, legal delivery than a crashed driver.", lesson:"Stop when your hours are up. Every time. No exceptions." },
      { text:"Drive to a truck stop 12 miles away, then stop for the night", outcome:"bad", result:"Still a Violation", detail:"12 miles over your hours is still a violation. The ELD records your location, speed, and duty status. If something happens in those 12 miles you have no legal defense.", lesson:"Stop when hours are up, not when it is convenient." },
    ]},
  { id:"s7", track:"all", title:"Failed Pre-Trip Discovery", icon:"🔧", category:"Compliance", difficulty:"Beginner",
    scenario:"Pre-trip at 5:30 AM. You find a visible crack in the left front brake chamber. Dispatch needs this load moving NOW. They say it is a quick fix and you will be fine.",
    options:[
      { text:"Take dispatch word for it and roll out", outcome:"bad", result:"OOSA Violation", detail:"Knowingly operating a vehicle with a known defect is an Out Of Service violation. If caught in inspection or post-accident investigation, you lose your CDL and face criminal liability.", lesson:"Never operate with a known defect. Period. No dispatcher authority supersedes safety law." },
      { text:"Document the defect on DVIR, refuse to move, demand repair", outcome:"good", result:"Correct Legal Position", detail:"Complete a Driver Vehicle Inspection Report documenting the defect. You are legally protected when you refuse to operate an unsafe vehicle. No shipper appointment is worth your CDL.", lesson:"Document defects on DVIR. You have the legal right and duty to refuse an unsafe truck." },
      { text:"Drive slowly and carefully to the first truck stop", outcome:"bad", result:"Still Operating Defective Equipment", detail:"There is no speed that makes a cracked brake chamber legal to operate. Slow driving does not fix defective brakes and does not protect you legally.", lesson:"Defective brakes make the truck OOS. No movement allowed until repaired." },
    ]},
  // BUSINESS - OWNER OP
  { id:"s8", track:"owner", title:"Low-Ball Broker Offer", icon:"📉", category:"Business", difficulty:"Intermediate",
    scenario:"Broker offers $1.85/mile on a 1,200-mile load. Your all-in cost is $1.72/mile. You have been parked 2 days. Market rate on DAT shows $2.15-2.30/mile for this lane.",
    options:[
      { text:"Take it - any money is better than sitting", outcome:"neutral", result:"Mistake with Context", detail:"Taking $1.85 when market is $2.15-2.30 trains this broker that you accept low rates. You also lose $360-540 vs. fair market. Two days sitting hurt but taking bad rates hurts longer.", lesson:"Low rates train brokers. Know your market before accepting." },
      { text:"Counter at $2.20/mile citing current DAT market data", outcome:"good", result:"Professional Negotiation", detail:"Countering with market data is standard practice. Most brokers have more room than their first offer. A confident, data-backed counter is respected and usually results in a rate increase.", lesson:"Always counter with market data. DAT rates give you leverage." },
      { text:"Walk away and call other brokers for the same lane", outcome:"good", result:"Market Discipline", detail:"With market at $2.15-2.30 this broker is low by $360-540. Spending 30 minutes working other brokers for market rate is a better return than 1,200 miles at below-market.", lesson:"Working multiple brokers for market rate is always worth the time." },
    ]},
  { id:"s9", track:"owner", title:"Broker Claims Non-Payment", icon:"💸", category:"Business", difficulty:"Expert",
    scenario:"A broker owes you $4,200 for a load delivered 45 days ago. They are now unresponsive. You need that money for next month's truck payment.",
    options:[
      { text:"Post a negative online review and move on", outcome:"bad", result:"Wrong First Step", detail:"A negative review without legal action leaves $4,200 on the table. Reviews are fine but they are not collection tools. You have legal remedies available.", lesson:"Use legal remedies before or alongside public complaints." },
      { text:"Send a formal demand letter and file a complaint with FMCSA", outcome:"good", result:"Right Protocol", detail:"Send a certified demand letter with payment deadline. File a complaint with FMCSA and the Better Business Bureau. Contact a transportation attorney if no response in 10 days.", lesson:"Demand letter + FMCSA complaint is the correct escalation path." },
      { text:"Accept partial payment and move on", outcome:"bad", result:"Accepting Theft", detail:"A broker who refuses to pay owes you the full amount. Accepting partial payment may waive your right to the remainder. Never accept partial without a written agreement.", lesson:"Never accept partial without a written settlement agreement." },
    ]},
  { id:"s10", track:"owner", title:"Truck Breakdown Cross-Country", icon:"🛠️", category:"Business", difficulty:"Intermediate",
    scenario:"Your turbo blew 350 miles from delivery. Shop estimate is $2,800 and 3 days. Broker threatens a $3,000 backcharge for late delivery. Your emergency fund has $2,100.",
    options:[
      { text:"Pay the repair, pay the backcharge, and absorb the loss", outcome:"bad", result:"Financial Damage", detail:"Accepting the backcharge without review costs you $5,800 total on a load you likely netted $800-1,200. Mechanical breakdown is force majeure in most carrier contracts.", lesson:"Mechanical breakdown is force majeure. Review your contract before accepting claims." },
      { text:"Review contract terms, respond in writing citing force majeure", outcome:"good", result:"Legally Sound", detail:"Most motor carrier contracts include force majeure clauses covering mechanical breakdowns. Respond in writing, citing the contract clause. Brokers often drop claims when challenged properly.", lesson:"Respond to claims in writing. Force majeure clauses protect you from mechanical backcharges." },
      { text:"Find a carrier to transload and complete the delivery", outcome:"good", result:"Above and Beyond", detail:"Arranging transload delivery shows professionalism and often results in the broker waiving claims entirely. You may owe the covering carrier a portion but protect your relationship and record.", lesson:"Transloading is the professional solution that preserves relationships and protects your record." },
    ]},
  // ROAD SKILL
  { id:"s11", track:"all", title:"Four-Wheeler Cut-Off", icon:"🚗", category:"Road Skill", difficulty:"Beginner",
    scenario:"On the interstate at 65 mph a sedan merges directly in front of you with less than 3 seconds of following distance. You need 6+ seconds to stop. You are fully loaded at 79,000 lbs.",
    options:[
      { text:"Brake hard and lean on your horn", outcome:"neutral", result:"Survivable but Dangerous", detail:"Hard braking with a full load risks rear-end collision from following traffic and can cause trailer swing. The horn does not shorten stopping distance.", lesson:"Hard braking is a last resort. Space management prevents this situation." },
      { text:"Move to available adjacent lane if clear, ease off throttle", outcome:"good", result:"Space Management", detail:"If the adjacent lane is clear, a smooth lane change creates immediate space. Simultaneously ease off throttle to increase following distance. Smooth inputs. No panic.", lesson:"Space management and smooth inputs prevent four-wheeler emergencies." },
      { text:"Flash lights and tailgate until they move over", outcome:"bad", result:"Aggressive Driving Violation", detail:"Tailgating and light-flashing are aggressive driving violations for a CMV driver. You would bear fault in any collision. Aggressive driving CSA violations are among the most severe.", lesson:"Never respond to four-wheeler aggression with aggression. Create space instead." },
    ]},
  { id:"s12", track:"all", title:"Wrong Turn - Low Bridge Ahead", icon:"🌉", category:"Road Skill", difficulty:"Intermediate",
    scenario:"Following GPS you turned on a county road. Sign ahead says 11 ft 8 in clearance. Your truck is 13 ft 6 in. The bridge is 200 yards ahead. No room to turn around. Traffic behind you.",
    options:[
      { text:"Go slowly - it might be close but you will fit", outcome:"bad", result:"Structural Collision", detail:"13 ft 6 in will not fit under 11 ft 8 in. A bridge strike damages or destroys your truck, potentially collapses the bridge, creates massive legal liability, and can be fatal. There is no close enough.", lesson:"If you cannot verify clearance you cannot go. Period. Ever." },
      { text:"Back up until you can safely turn around", outcome:"good", result:"Correct and Necessary", detail:"Backing up on a public road requires hazard lights, good mirrors work, and possibly a spotter. It is inconvenient and might take 20 minutes. It is the only option when you cannot clear a bridge.", lesson:"Back up no matter how inconvenient. A bridge strike ends careers and lives." },
      { text:"Ask traffic behind you to back up so you can reverse", outcome:"good", result:"Collaborative but Slow", detail:"Getting traffic behind you to back up is sometimes necessary when backing alone is unsafe. Hazard lights on, get out, communicate with other drivers. This is the safe approach.", lesson:"Use other drivers as safety resources when necessary. Communicate clearly." },
    ]},
  { id:"s13", track:"all", title:"Losing Load at Highway Speed", icon:"📦", category:"Road Skill", difficulty:"Expert",
    scenario:"At 70 mph on I-10 a strap on your flatbed snaps. You can see tarps shifting in your mirrors. One side of the load is lifting. Traffic is all around you.",
    options:[
      { text:"Maintain speed to minimize the transition - pull off at next exit", outcome:"bad", result:"Catastrophic Risk", detail:"An unsecured load at 70 mph is a road hazard that can kill the drivers behind you. Continuing to the next exit means traveling up to 2+ miles with potential load separation.", lesson:"Unsecured load = pull over immediately. No exit is acceptable." },
      { text:"Signal, check mirrors, pull over immediately, activate hazards", outcome:"good", result:"Correct Emergency Response", detail:"Pull to the safest available spot immediately. Activate emergency flashers and set triangles at proper distances. Inspect and re-secure before moving. Call dispatch.", lesson:"Immediate stop, hazards, triangles, inspect and re-secure. In that order." },
      { text:"Slow down gradually to reduce aerodynamic lift on the tarp", outcome:"bad", result:"Inadequate Response", detail:"Slowing down while still moving does not re-secure a failed strap. Load shift at any speed is a legal and safety emergency requiring immediate stop.", lesson:"Slowing down does not fix an unsecured load. Stop immediately." },
    ]},
  // COMPANY DRIVER SPECIFIC
  { id:"s14", track:"company", title:"Dispatcher Pressure to Violate HOS", icon:"📱", category:"Business", difficulty:"Intermediate",
    scenario:"Your dispatcher calls and tells you to push past your HOS limit to make a detention-sensitive load. They say they will cover you if anything happens.",
    options:[
      { text:"Trust the dispatcher - they said they would cover you", outcome:"bad", result:"You Will Not Be Covered", detail:"Dispatchers cannot legally indemnify a driver for HOS violations. If you are inspected, in an accident, or your ELD is audited, the violation is yours. No dispatcher has protected a driver from an HOS citation.", lesson:"No one can cover an HOS violation. The driver always owns it." },
      { text:"Refuse professionally and document the request in writing", outcome:"good", result:"Correct and Protected", detail:"Declining an illegal instruction and documenting it in writing protects you. Text or email creates a record. If you are later pressured or terminated for refusing, documentation protects you legally.", lesson:"Refuse illegal instructions. Document everything in writing. This protects your CDL and your job." },
      { text:"Compromise by going 30 minutes over - it is a small violation", outcome:"bad", result:"Still a Federal Violation", detail:"There is no small HOS violation. 31 minutes over is the same federal violation as 3 hours over. The only question is whether you get caught.", lesson:"Any HOS violation is a federal violation. There is no minor version." },
    ]},
  { id:"s15", track:"company", title:"Customer Conflict at Delivery", icon:"🏭", category:"Business", difficulty:"Beginner",
    scenario:"At delivery the receiver refuses your load, claiming damage. You inspected the freight at pickup and it was in perfect condition. You have photos. They are demanding you take it back.",
    options:[
      { text:"Argue that the damage happened on their end and refuse to take it back", outcome:"bad", result:"Escalation Without Resolution", detail:"Getting into a dock argument accomplishes nothing and makes you look unprofessional. Even if you are right, you need documented escalation not a shouting match.", lesson:"Document everything and escalate professionally. Never dock-argue." },
      { text:"Show your pickup photos, note dispute on BOL, call dispatch", outcome:"good", result:"Professional and Protected", detail:"Your photos are your evidence. Note the refusal and reason on the BOL, call dispatch immediately, and do not leave without proper documentation. This is textbook dispute resolution.", lesson:"Photos + BOL notation + immediate dispatch contact = proper freight dispute protocol." },
      { text:"Just take the load back without documentation", outcome:"bad", result:"Serious Mistake", detail:"Accepting a refused load without documenting the dispute creates liability. Your company may not cover the claim, the shipper will dispute payment, and you have no legal protection.", lesson:"Never accept or return freight without full written documentation of the dispute." },
    ]},
  // ADVANCED / OWNER OP
  { id:"s16", track:"owner", title:"Insurance Claim After Minor Accident", icon:"🚘", category:"Business", difficulty:"Expert",
    scenario:"At slow speed in a truck stop you clipped a parked trailer. No injuries. Minor damage to both. The other driver wants to exchange insurance and handle it privately to avoid claims.",
    options:[
      { text:"Exchange info privately - it is minor damage and you need no claim", outcome:"bad", result:"Serious Risk", detail:"Private settlements in trucking are legally complex. If the other driver later files a claim through insurance, your failure to report may void your coverage or appear as fraud.", lesson:"Never settle privately in trucking. Always report to your insurance carrier." },
      { text:"Call your insurance immediately and report the incident", outcome:"good", result:"Correct Protocol", detail:"Report every incident to your insurance carrier, even minor ones. Let them assess and handle the claim. That is what your premium pays for. Failing to report can void coverage.", lesson:"Report every incident to insurance immediately. That is what coverage is for." },
      { text:"File a police report and let insurance handle it", outcome:"good", result:"Also Correct", detail:"Getting law enforcement involved in truck stop incidents provides an official record, which protects both parties. File the police report, notify your insurance, and follow their guidance.", lesson:"Police report + insurance report = full protection. Both are correct." },
    ]},
  { id:"s17", track:"all", title:"Carbon Monoxide Warning in Cab", icon:"⚠️", category:"Emergency", difficulty:"Expert",
    scenario:"Your CO alarm goes off while driving on the highway. You feel slightly dizzy and have a headache. It is 28 degrees outside. Your cab has been sealed for warmth.",
    options:[
      { text:"Open windows, exit at next exit, stop for fresh air", outcome:"bad", result:"Dangerous Delay", detail:"Carbon monoxide incapacitates quickly. By the time you reach the next exit your decision-making is already impaired. Every minute matters in a CO event.", lesson:"CO alarm means pull over immediately and evacuate. No delays." },
      { text:"Pull over immediately, open all windows and doors, evacuate cab", outcome:"good", result:"Life-Saving Response", detail:"CO is odorless and colorless. Trust the alarm. Pull over at the first safe spot, open everything for ventilation, exit the cab, and call 911. Do not re-enter until emergency services clear it.", lesson:"Immediate evacuation is the only correct CO response. Trust the alarm." },
      { text:"Turn the heater off and keep driving to a truck stop", outcome:"bad", result:"Continued CO Exposure", detail:"Turning off the heater does not remove CO already in the cab. Continuing to drive while exposed to CO and feeling dizzy means you are driving impaired. This ends in a crash.", lesson:"CO alarms require immediate stop and evacuation. No driving." },
    ]},
  { id:"s18", track:"all", title:"Winter Storm Closure Decision", icon:"❄️", category:"Road Skill", difficulty:"Intermediate",
    scenario:"I-80 Wyoming just issued a chain requirement advisory. Your chains are back at the terminal in Cheyenne. You are 40 miles from the next truck stop. Temp is 12 degrees and dropping.",
    options:[
      { text:"Push through - you have good winter tires and experience", outcome:"bad", result:"Judgment and Legal Error", detail:"Chain requirement advisories carry fines for non-compliance. More importantly, I-80 Wyoming in a winter storm with no chains on a loaded truck is one of the most dangerous road situations in America.", lesson:"Chain requirements are law. No chains means pull over, not push through." },
      { text:"Pull over at the next safe area and wait for conditions to clear", outcome:"good", result:"Right Call", detail:"Pulling over protects you legally, protects your CDL, and keeps you alive. Call dispatch with location and situation. Most carriers have weather protocols. Follow them.", lesson:"Waiting out a chain requirement is always the right call. Loads can be rescheduled. Lives cannot." },
      { text:"Turn around and go back to Cheyenne for your chains", outcome:"good", result:"Compliant Option", detail:"If it is safe to turn around and get proper equipment, this is a valid option. It costs time but puts you in compliance. Discuss with dispatch before deciding.", lesson:"Compliance with chain requirements is non-negotiable. Getting proper equipment is always an option." },
    ]},
  { id:"s19", track:"all", title:"Medical Emergency While Driving", icon:"🚑", category:"Emergency", difficulty:"Expert",
    scenario:"You are driving on a 4-lane highway and feel severe chest pain radiating to your left arm. You feel short of breath. You are 5 miles from an exit.",
    options:[
      { text:"Push to the next exit and call for help there", outcome:"bad", result:"Potentially Fatal Decision", detail:"Chest pain radiating to the arm is a classic heart attack presentation. You have minutes. Driving 5 miles in a 40-ton truck while having a cardiac event is an extreme danger to yourself and everyone on the road.", lesson:"Medical emergency means pull over NOW. Do not drive to an exit. Every second counts." },
      { text:"Pull to the shoulder immediately, activate hazards, call 911", outcome:"good", result:"Correct Life-Saving Response", detail:"Pull to the right shoulder immediately. Turn on all emergency lights. Call 911. Unlock your door if possible. Tell the 911 operator you are a commercial truck driver with medical distress. Stay on the line.", lesson:"Immediate stop, hazards, 911. This is the only correct response to a medical emergency." },
      { text:"Call dispatch first to let them know what is happening", outcome:"bad", result:"Wrong Priority Order", detail:"Dispatch cannot send help or call 911 faster than you can. Every second spent on a dispatch call during a cardiac event is a second not spent getting emergency services to your exact location.", lesson:"911 always before dispatch in a medical emergency. Location accuracy saves lives." },
    ]},
  { id:"s20", track:"beginner", title:"First Solo Dock Backup", icon:"🏭", category:"Road Skill", difficulty:"Beginner",
    scenario:"Your first solo delivery. Tight dock, 4 trailers on each side. A dock foreman is watching. You have attempted 4 times and cannot get the trailer aligned. Your heart is pounding.",
    options:[
      { text:"Keep trying - you will get it eventually", outcome:"bad", result:"Pride Over Safety", detail:"After 4 failed attempts in a tight dock with observers, continuing to attempt without resetting creates risk of contact with adjacent trailers. Dock workers have seen this a thousand times.", lesson:"After multiple failed attempts, reset completely. Every experienced driver has done this." },
      { text:"Get out, G.O.A.L., take a breath, ask for a spotter", outcome:"good", result:"Professional Move", detail:"Get Out And Look. Reset your reference points. Ask the foreman for a spotter - they do this every day and will appreciate your professionalism over your ego. You will nail it with fresh eyes.", lesson:"G.O.A.L. every time. Asking for a spotter is professionalism, not weakness." },
      { text:"Call your trainer and have them talk you through it", outcome:"good", result:"Smart Use of Resources", detail:"Calling your trainer is a legitimate option on early solo runs. Getting verbal guidance resets your mental state as much as your physical approach.", lesson:"Using your training network on early solos is professional. You are not expected to know everything yet." },
    ]},
];

// ─── GLOSSARY ─────────────────────────────────────────────────────────────────
const GLOSSARY = [
  { term:"BOL (Bill of Lading)", def:"The legal contract between shipper and carrier documenting freight type, quantity, condition, and delivery terms. Always inspect cargo before signing." },
  { term:"Bobtail", def:"A semi truck operating without a trailer attached. Bobtail trucks handle differently due to weight distribution - braking distances change significantly." },
  { term:"CDL (Commercial Drivers License)", def:"Federal license required to operate commercial vehicles. Class A: combination vehicles. Class B: single vehicles over 26,001 lbs. Class C: special hazmat or passenger." },
  { term:"CSA Score", def:"FMCSA Compliance, Safety, Accountability score based on inspections and violations. Lower is better. High scores trigger interventions and affect employment." },
  { term:"Deadhead Miles", def:"Miles driven with an empty trailer generating no revenue. All operating costs still apply. Minimizing deadhead improves profitability significantly." },
  { term:"DOT Physical", def:"Medical examination required to maintain CDL. Must be completed by a certified medical examiner. Valid for up to 24 months for healthy drivers." },
  { term:"DVIR (Driver Vehicle Inspection Report)", def:"Required written report documenting pre-trip and post-trip vehicle inspection. Must note any defects. Kept for 90 days." },
  { term:"ELD (Electronic Logging Device)", def:"Federally mandated device that automatically records driving time and duty status. Replaced paper logs in 2019 for most carriers." },
  { term:"Fifth Wheel", def:"The coupling plate on the tractor that accepts the trailer kingpin. Must be properly greased, locked, and inspected before every trip." },
  { term:"Factoring", def:"Financial service where a company buys your receivables at a discount (2-5%) and pays immediately. Solves cash flow issues for new owner-operators." },
  { term:"G.O.A.L.", def:"Get Out And Look. The mandatory practice of physically checking your surroundings before and during any backing maneuver. Non-negotiable safety rule." },
  { term:"Gross Combination Weight Rating (GCWR)", def:"Maximum operating weight of a tractor-trailer combination including vehicle, cargo, fuel, and passengers as specified by manufacturer." },
  { term:"HOS (Hours of Service)", def:"FMCSA rules limiting driving and on-duty time. Key limits: 11 hrs driving, 14 hr window, 30-min break after 8 hrs, 60/70-hr weekly limit." },
  { term:"IFTA (International Fuel Tax Agreement)", def:"Agreement between US states and Canadian provinces allowing truckers to report fuel taxes in their base state. Quarterly filings required." },
  { term:"Kingpin", def:"The steel pin on the underside of a trailer that locks into the fifth wheel. Must be properly seated and locked before movement." },
  { term:"MC Number", def:"Motor Carrier Number issued by FMCSA authorizing operation as a for-hire carrier. Required before hauling loads for brokers or shippers." },
  { term:"OOS (Out of Service)", def:"Designation by DOT inspector placing driver or vehicle in Out of Service status. Vehicle cannot move until violation is corrected." },
  { term:"Per Diem", def:"Tax-free daily allowance for meals and incidentals when traveling away from home. Currently $69/day for truck drivers under IRS guidelines." },
  { term:"Placard", def:"Required signage on vehicles transporting hazardous materials. Indicates hazmat class. Specific placards required for specific materials and quantities." },
  { term:"Reefer", def:"Refrigerated trailer. Temperature-controlled units for perishable freight. Requires additional certification and knowledge of temperature management." },
  { term:"Tandems", def:"The paired rear axle groups on a semi trailer. Sliding tandems forward or backward redistributes weight between drive and trailer axles." },
  { term:"Tare Weight", def:"The weight of the empty vehicle without cargo. GVWR minus tare weight equals payload capacity." },
  { term:"UCR (Unified Carrier Registration)", def:"Annual registration required for all interstate commercial motor carriers. Fee based on fleet size. Non-compliance results in fines." },
];


