// ─── GLOBAL BIG EARL CHAT MODAL ───────────────────────────────────────────────
function EarlModal({ onClose, profile }) {
  const [messages, setMessages] = useState([
    { role:"assistant", text:"What's on your mind, driver? Ask me anything - routes, regulations, rates, backing, breakdowns. Thirty years behind the wheel and I've seen it all." }
  ]);
  const [input, setInput]     = useState("");
  const [loading, setLoading] = useState(false);
  const scrollRef             = useRef(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const send = async () => {
    const q = input.trim();
    if (!q || loading) return;
    setInput("");
    const newMessages = [...messages, { role:"user", text:q }];
    setMessages(newMessages);
    setLoading(true);
    try {
      const history = newMessages.map(m => ({ role: m.role === "assistant" ? "assistant" : "user", content: m.text }));
      const response = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 400,
          system: "You are Big Earl, a no-nonsense 30-year veteran trucker with 3.2 million miles under your belt. You speak plainly, directly, and always from real experience. You help CDL drivers, company drivers, and owner-operators with any question - regulations, routes, rates, backing, breakdowns, dealing with brokers, DOT inspections, dispatchers, you name it. Keep answers under 4 sentences. Be direct. No fluff. Real talk only.",
          messages: history,
        })
      });
      const data = await response.json();
      const reply = (data.content||[]).filter(b=>b.type==="text").map(b=>b.text).join("") || "Radio's cutting out on me. Try again.";
      setMessages(m => [...m, { role:"assistant", text:reply }]);
    } catch(e) {
      // Fallback: use keyword matching for common questions when API is blocked
      const q = newMessages[newMessages.length-1].text.toLowerCase();
      let fallback = "";

      if (q.includes("dot") || q.includes("llc") || q.includes("authority") || q.includes("mc number")) {
        fallback = "Your DOT number is tied to whoever applied - person or LLC. If you got it in your personal name, you can still form an LLC and transfer the authority over. Call FMCSA at 1-800-832-5660 or use their online portal to update the entity. Do it before you sign any contracts so your liability is protected from day one.";
      } else if (q.includes("rate") || q.includes("per mile") || q.includes("broker") || q.includes("load")) {
        fallback = "Never take the first number a broker gives you. Their opening offer is the floor - they have room to go up. Know your cost per mile before you pick up the phone, and never haul for less than that number no matter what they say. Counter every single time, even if you only get 5 cents more.";
      } else if (q.includes("hos") || q.includes("hours of service") || q.includes("14 hour") || q.includes("11 hour")) {
        fallback = "The 14-hour clock is the one that bites people. It starts the second you come on duty and it does not stop for breaks, traffic, or anything else. Once that clock runs out you are done driving - period. Plan your day around the 14, not around the miles.";
      } else if (q.includes("backing") || q.includes("dock") || q.includes("reverse")) {
        fallback = "Get Out And Look every single time before you back. I do not care how experienced you are. Walk the spot, check your clearances, then back slow. The accidents that end careers are the ones drivers thought they knew. GOAL - burn that into your head.";
      } else if (q.includes("pre-trip") || q.includes("inspection") || q.includes("dot inspection")) {
        fallback = "A pre-trip is not a formality - it is your legal protection. If something breaks on the road and you did not document it on your inspection report, that is on you. Take 30 minutes, do it right, sign it. That paper has saved more drivers from lawsuits than anything else.";
      } else if (q.includes("tire") || q.includes("blowout") || q.includes("flat")) {
        fallback = "Steer tire blowout - grip the wheel, slight throttle to stabilize, do NOT brake hard. Let the truck slow naturally then ease onto the shoulder. Braking during a steer blowout is how trucks end up in the ditch. Stay calm, hold your line, and get off the road smooth.";
      } else if (q.includes("sleep") || q.includes("fatigue") || q.includes("tired")) {
        fallback = "There is no load worth dying for. If you are fighting to keep your eyes open, pull over. A 20-minute power nap in a rest area is not weakness - it is professional judgment. The drivers who push through fatigue are the ones making the news for the wrong reasons.";
      } else if (q.includes("ifta") || q.includes("fuel tax") || q.includes("quarterly")) {
        fallback = "IFTA is simple once you understand it - you owe fuel tax where you drive, you pay it where you fuel up, and IFTA reconciles the difference quarterly. Keep every receipt, track your miles by state, and file January 31, April 30, July 31, October 31. Miss a deadline and you are paying penalties.";
      } else if (q.includes("insurance") || q.includes("cargo insurance") || q.includes("liability")) {
        fallback = "Minimum you need as an owner-op: $750,000 primary liability, $100,000 cargo, and a bobtail policy for when you are running without a trailer. Do not cheap out on cargo insurance - one claim for a damaged load can wipe out months of profit. Shop Progressive, Great West, and Owner Operator Independent Drivers Association.";
      } else if (q.includes("tax") || q.includes("deduction") || q.includes("per diem")) {
        fallback = "Per diem is $69 a day for every day you are away from home - that alone can save you $5,000 to $8,000 a year in taxes. Get a trucking-specific accountant, not a general one. ATBS handles over 70,000 owner-operators and they know every deduction that applies to us specifically.";
      } else if (q.includes("dispatcher") || q.includes("dispatch") || q.includes("pressure")) {
        fallback = "No dispatcher can legally force you to drive in unsafe conditions or violate HOS. If they pressure you, tell them clearly: I am not able to do this legally and safely. Document it in writing. Your CDL is your livelihood - no load is worth losing it over a dispatcher who is not in the truck with you.";
      } else if (q.includes("weather") || q.includes("ice") || q.includes("snow") || q.includes("wind")) {
        fallback = "In bad weather - slow down before you need to, not after. Your stopping distance doubles on wet roads and triples on ice. If it gets bad enough that you are white-knuckling it, you are already past the point where you should have pulled over. There is no shame in waiting it out at a truck stop.";
      } else {
        fallback = "Good question. The API is running in preview mode right now so I am giving you my standard take. Once this app is deployed, you will get my full real-time response. Deploy to Vercel and I will be fully live - no limitations.";
      }

      setMessages(m => [...m, { role:"assistant", text:fallback }]);
    }
    setLoading(false);
  };

  return (
    <div style={{
      position:"fixed", inset:0, zIndex:10000,
      background:"rgba(0,0,0,0.85)",
      display:"flex", flexDirection:"column",
      justifyContent:"flex-end",
    }} onClick={onClose}>
      <div onClick={e=>e.stopPropagation()} style={{
        background:"#0d0c0a",
        borderRadius:"24px 24px 0 0",
        border:"1px solid #F5A62330",
        borderBottom:"none",
        maxHeight:"80vh",
        display:"flex", flexDirection:"column",
        overflow:"hidden",
      }}>
        {/* Header */}
        <div style={{
          background:"linear-gradient(135deg,#1a1006,#0d0c0a)",
          borderBottom:"1px solid #F5A62320",
          padding:"16px 20px",
          display:"flex", alignItems:"center", gap:12, flexShrink:0,
        }}>
          <div style={{ fontSize:36 }}>🧔🏿</div>
          <div style={{ flex:1 }}>
            <div style={{ color:"#F5A623", fontSize:14, fontFamily:"Oswald,sans-serif", fontWeight:700, letterSpacing:1 }}>
              BIG EARL
            </div>
            <div style={{ color:"#8899AA", fontSize:11, fontFamily:"Barlow,sans-serif" }}>
              30 years · 3.2M miles · Ask anything
            </div>
          </div>
          <button onClick={onClose} style={{
            background:"rgba(255,255,255,0.08)", border:"none",
            color:"#fff", fontSize:18, width:34, height:34,
            borderRadius:"50%", cursor:"pointer",
            display:"flex", alignItems:"center", justifyContent:"center",
          }}>✕</button>
        </div>

        {/* Messages */}
        <div ref={scrollRef} style={{
          flex:1, overflowY:"auto", padding:"16px 16px 8px",
          display:"flex", flexDirection:"column", gap:10,
          minHeight:200,
        }}>
          {messages.map((msg, i) => (
            <div key={i} style={{
              display:"flex", gap:8,
              justifyContent: msg.role==="user" ? "flex-end" : "flex-start",
              alignItems:"flex-end",
            }}>
              {msg.role==="assistant" && (
                <div style={{ fontSize:22, flexShrink:0, marginBottom:2 }}>🧔🏿</div>
              )}
              <div style={{
                maxWidth:"80%",
                background: msg.role==="user" ? "#F5A62322" : "#1a1810",
                border:`1px solid ${msg.role==="user" ? "#F5A62340" : "#2a2820"}`,
                borderRadius: msg.role==="user" ? "18px 18px 4px 18px" : "18px 18px 18px 4px",
                padding:"10px 14px",
                color: msg.role==="user" ? "#F5A623" : "#D4C9A8",
                fontSize:13, fontFamily:"Barlow,sans-serif", lineHeight:1.6,
              }}>
                {msg.text}
              </div>
              {msg.role==="user" && (
                <div style={{ fontSize:20, flexShrink:0 }}>{profile?.avatar||"🧑‍✈️"}</div>
              )}
            </div>
          ))}
          {loading && (
            <div style={{ display:"flex", gap:8, alignItems:"flex-end" }}>
              <div style={{ fontSize:22 }}>🧔🏿</div>
              <div style={{ background:"#1a1810", border:"1px solid #2a2820", borderRadius:"18px 18px 18px 4px", padding:"10px 16px" }}>
                <div style={{ display:"flex", gap:4 }}>
                  {[0,1,2].map(i => (
                    <div key={i} style={{
                      width:6, height:6, borderRadius:"50%", background:"#F5A623",
                      animation:`bounce .8s ease ${i*0.15}s infinite`,
                    }}/>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Input */}
        <div style={{
          padding:"12px 16px 28px", flexShrink:0,
          borderTop:"1px solid #2a2820",
          background:"#0d0c0a",
          display:"flex", gap:10, alignItems:"flex-end",
        }}>
          <textarea
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => { if(e.key==="Enter" && !e.shiftKey){ e.preventDefault(); send(); }}}
            placeholder="Ask Earl anything..."
            rows={1}
            style={{
              flex:1, background:"#1a1810", border:"1px solid #3a3020",
              borderRadius:12, padding:"10px 14px",
              color:"#D4C9A8", fontSize:13, fontFamily:"Barlow,sans-serif",
              resize:"none", outline:"none", lineHeight:1.5,
              maxHeight:80, overflowY:"auto",
            }}
          />
          <button onClick={send} disabled={!input.trim()||loading} style={{
            width:42, height:42, borderRadius:12, flexShrink:0,
            background: (!input.trim()||loading) ? "#2a2820" : "#F5A623",
            border:"none", cursor: (!input.trim()||loading) ? "not-allowed" : "pointer",
            display:"flex", alignItems:"center", justifyContent:"center",
            fontSize:18, transition:"background .2s",
          }}>▶</button>
        </div>
      </div>
    </div>
  );
}

export default function App() {
  const [appState, setAppState]     = useState("splash");
  const [tab, setTab]               = useState("home");
  const [track, setTrack]           = useState(null);
  const [earlOpen, setEarlOpen]     = useState(false);
  const [screen, setScreen]         = useState("home");
  const [screenData, setScreenData] = useState({});
  const [progress, setProgress]     = useState({
    completed:[], simScores:{}, cdlScores:[], xp:0,
    streak:0, lastActive:null,
    bookmarked:[], missedQuestions:[],   // Step 1+2: bookmarks & missed Q
  });
  const [profile, setProfile]       = useState({ name:"Driver", plan:"free", state:"Texas" });
  const [animIn, setAnimIn]         = useState(true);
  // streak logic
  const scrollRef = useRef(null);
  useEffect(() => {
    const today = new Date().toDateString();
    if (progress.lastActive !== today) {
      const yesterday = new Date(Date.now()-86400000).toDateString();
      const newStreak = progress.lastActive === yesterday ? (progress.streak||0)+1 : 1;
      setProgress(p => ({...p, streak:newStreak, lastActive:today}));
    }
  }, []);

  const go = (ns, data) => {
    setAnimIn(false);
    setTimeout(() => {
      setScreen(ns); setScreenData(data || {});
      setAnimIn(true);
      if (scrollRef.current) scrollRef.current.scrollTop = 0;
    }, 160);
  };
  const switchTab = (t, sc) => { setTab(t); go(sc || t); };
  const completeLesson = (id, xp) => {
    setProgress(p => ({
      ...p,
      completed: p.completed.includes(id) ? p.completed : [...p.completed, id],
      xp: p.completed.includes(id) ? p.xp : p.xp + xp,
    }));
  };
  const totalLessons = Object.values(LESSONS).flat().length;
  const nav = [
    { id:"home",      icon:"⬡",   label:"Home" },
    { id:"learn",     icon:"📚",   label:"Learn",     sc:"learn" },
    { id:"sim",       icon:"🎮",   label:"Simulate",  sc:"sim" },
    { id:"cdl",       icon:"📝",   label:"CDL Prep",  sc:"cdl" },
    { id:"news",      icon:"📰",   label:"News",      sc:"news" },
    { id:"community", icon:"💬",   label:"Community", sc:"community" },
    { id:"profile",   icon:"👤",   label:"Profile" },
  ];

  if (appState === "splash") return <SplashScreen onStart={() => setAppState("onboarding")} />;
  if (appState === "onboarding") return <OnboardingScreen onComplete={(t) => { setTrack(t); setAppState("main"); }} />;

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Oswald:wght@300;400;500;600;700&family=Barlow:ital,wght@0,300;0,400;0,500;0,600;0,700;1,400&display=swap');
        *{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent;}
        body{background:#0D0F14;}
        ::-webkit-scrollbar{width:2px;}
        ::-webkit-scrollbar-thumb{background:#2E3447;border-radius:2px;}
        @keyframes pulse{0%,100%{opacity:1}50%{opacity:.3}}
        @keyframes pulse{0%,100%{transform:scale(1);box-shadow:0 4px 20px rgba(245,166,35,0.4)}50%{transform:scale(1.08);box-shadow:0 6px 28px rgba(245,166,35,0.65)}}
        @keyframes bounce{0%,100%{transform:translateY(0);opacity:.4}50%{transform:translateY(-4px);opacity:1}}
        @keyframes slideUp{from{opacity:0;transform:translateY(18px)}to{opacity:1;transform:translateY(0)}}
        @keyframes fadeIn{from{opacity:0}to{opacity:1}}
        @keyframes glow{0%,100%{box-shadow:0 0 10px rgba(245,166,35,.2)}50%{box-shadow:0 0 28px rgba(245,166,35,.6)}}
        @keyframes roadScroll{from{background-position:0 0}to{background-position:100px 0}}
        button:active{opacity:.8;}
        input::placeholder{color:#555E78;}
      `}</style>
      <div style={{ fontFamily:"Oswald,sans-serif", background:C.bg, minHeight:"100dvh", maxWidth:430, margin:"0 auto", display:"flex", flexDirection:"column" }}>
        <div ref={scrollRef} style={{ flex:1, overflowY:"auto", overflowX:"hidden", paddingBottom:80, position:"relative" }}>
          {/* Background - the trucker photo, very subtle */}
          <div style={{
            position:"fixed", inset:0, zIndex:0, pointerEvents:"none",
            backgroundImage:`url(${BG_IMAGE})`,
            backgroundSize:"cover", backgroundPosition:"center 25%",
            opacity:0.08,
          }}/>
          {/* Dark overlay - keeps all text 100% readable */}
          <div style={{
            position:"fixed", inset:0, zIndex:0, pointerEvents:"none",
            background:"rgba(10,11,16,0.91)",
          }}/>
          <div style={{ position:"relative", zIndex:1, opacity:animIn?1:0, transform:animIn?"translateY(0)":"translateY(12px)", transition:"opacity .16s ease,transform .16s ease" }}>
            {tab==="home"      && <DashboardScreen switchTab={switchTab} go={go} track={track} setTrack={setTrack} progress={progress} totalLessons={totalLessons} profile={profile} />}
            {tab==="learn"     && screen==="learn"      && <LearnScreen go={go} track={track} setTrack={setTrack} progress={progress} />}
            {tab==="learn"     && screen==="lesson"     && <LessonScreen go={go} track={track} data={screenData} progress={progress} completeLesson={completeLesson} />}
            {tab==="sim"       && screen==="sim"        && <SimListScreen go={go} track={track} progress={progress} />}
            {tab==="sim"       && screen==="simPlay"    && <SimPlayScreen go={go} track={track} data={screenData} setProgress={setProgress} />}
            {tab==="cdl"       && screen==="cdl"        && <CDLScreen go={go} progress={progress} profile={profile} track={track} />}
            {tab==="cdl"       && screen==="cdlTest"    && <CDLTestScreen go={go} data={screenData} setProgress={setProgress} progress={progress} />}
            {tab==="cdl"       && screen==="cdlResults" && <CDLResultsScreen go={go} data={screenData} />}
            {tab==="cdl"       && screen==="cdlBookmarks" && <BookmarksScreen go={go} progress={progress} setProgress={setProgress} />}
            {tab==="news"      && screen==="news"      && <NewsScreen go={go} />}
            {tab==="community" && <CommunityScreen go={go} profile={profile} progress={progress} setProgress={setProgress} />}
            {tab==="tools"     && screen==="tools"      && <ToolsScreen go={go} />}
            {tab==="tools"     && screen==="rateCalc"   && <RateCalculatorScreen go={go} />}
            {tab==="tools"     && screen==="pretrip"    && <PreTripScreen go={go} />}
            {tab==="profile"   && screen==="profile"  && <ProfileScreen go={go} profile={profile} setProfile={setProfile} progress={progress} track={track} setTrack={setTrack} />}
          {tab==="profile"   && screen==="feedback" && <FeedbackScreen go={go} profile={profile} />}
          </div>
        </div>
        <div style={{ position:"fixed", bottom:0, left:"50%", transform:"translateX(-50%)", width:"100%", maxWidth:430, background:"rgba(8,10,14,0.99)", backdropFilter:"blur(20px)", WebkitBackdropFilter:"blur(20px)", borderTop:`1px solid rgba(255,255,255,0.08)`, display:"flex", zIndex:100, paddingBottom:"env(safe-area-inset-bottom,6px)" }}>
          {nav.map(t => (
            <button key={t.id} onClick={() => switchTab(t.id, t.sc)} style={{ flex:1, background:"none", border:"none", cursor:"pointer", padding:"8px 1px 5px", display:"flex", flexDirection:"column", alignItems:"center", gap:2 }}>
              <span style={{ fontSize:t.id==="home"?14:16, opacity:tab===t.id?1:.4, transition:"opacity .2s" }}>{t.icon}</span>
              <span style={{ fontSize:8, fontFamily:"Barlow,sans-serif", fontWeight:600, letterSpacing:.3, color:tab===t.id?C.amber:C.gray2, transition:"color .2s" }}>{t.label}</span>
              {tab===t.id && <div style={{ width:14, height:2, background:C.amber, borderRadius:1 }} />}
            </button>
          ))}
        </div>
      </div>
      {/* Floating Big Earl Button - visible on all screens */}
      {appState === "main" && !earlOpen && (
        <button
          onClick={() => setEarlOpen(true)}
          style={{
            position:"fixed", bottom:90, right:18, zIndex:9000,
            width:54, height:54, borderRadius:"50%",
            background:"linear-gradient(135deg,#F5A623,#E8941A)",
            border:"2px solid #F5A62360",
            boxShadow:"0 4px 20px rgba(245,166,35,0.4)",
            cursor:"pointer", fontSize:26,
            display:"flex", alignItems:"center", justifyContent:"center",
            animation:"pulse 2s ease infinite",
          }}>
          🧔🏿
        </button>
      )}

      {/* Big Earl Global Chat Modal */}
      {earlOpen && <EarlModal onClose={() => setEarlOpen(false)} profile={profile} />}

    </>
  );
}

// ─── SPLASH ───────────────────────────────────────────────────────────────────
