function GlossaryScreen({ go }) {
  const [search, setSearch] = useState("");
  const filtered = GLOSSARY.filter(g => g.term.toLowerCase().includes(search.toLowerCase()) || g.def.toLowerCase().includes(search.toLowerCase()));
  return (
    <div>
      <PageHeader title="Glossary" subtitle="TRUCKING TERMS" color={C.amber} back="Resources" onBack={() => go("resources")} />
      <div style={{ padding:"14px 24px" }}>
        <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search terms..." style={{ width:"100%", background:C.bg2, border:`1px solid ${C.border}`, borderRadius:10, padding:"12px 14px", color:C.offWhite, fontSize:13, fontFamily:"Barlow,sans-serif", outline:"none", marginBottom:16 }} />
        <div style={{ color:C.gray2, fontSize:11, fontFamily:"Barlow,sans-serif", marginBottom:12 }}>{filtered.length} terms</div>
        {filtered.map((item, i) => (
          <Card key={i} style={{ marginBottom:8, padding:14 }}>
            <div style={{ color:C.amber, fontSize:13, fontWeight:600, marginBottom:6 }}>{item.term}</div>
            <div style={{ color:C.offWhite, fontSize:12, fontFamily:"Barlow,sans-serif", lineHeight:1.65 }}>{item.def}</div>
          </Card>
        ))}
      </div>
    </div>
  );
}

function TipsScreen({ go }) {
  return (
    <div>
      <PageHeader title="Pro Tips" subtitle="VETERAN DRIVER ADVICE" color={C.green} back="Resources" onBack={() => go("resources")} />
      <div style={{ padding:"18px 24px" }}>
        {TIPS.map((item, i) => (
          <div key={i} style={{ background:C.bg2, border:`1px solid ${C.border}`, borderRadius:14, padding:18, display:"flex", gap:14, marginBottom:12, animation:`slideUp .3s ease ${i*.05}s both` }}>
            <div style={{ fontSize:28, flexShrink:0 }}>{item.icon}</div>
            <div>
              <div style={{ color:C.green, fontSize:13, fontWeight:600, marginBottom:5 }}>{item.title}</div>
              <div style={{ color:C.offWhite, fontSize:12, fontFamily:"Barlow,sans-serif", lineHeight:1.7 }}>{item.tip}</div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function NewsScreen({ go }) {
  const [activeTab, setActiveTab]       = useState("feed");
  const [articles, setArticles]         = useState([]);
  const [digest, setDigest]             = useState(null);
  const [loading, setLoading]           = useState(false);
  const [digestLoading, setDigestLoading] = useState(false);
  const [lastFetched, setLastFetched]   = useState(null);
  const [error, setError]               = useState(null);
  const [activeCategory, setActiveCategory] = useState("All");

  const CATEGORIES = ["All","Regulations","Fuel","Weather","FMCSA","Jobs","Safety","Business"];

  const CAT_ICONS = {
    "All":"📰", "Regulations":"📋", "Fuel":"⛽", "Weather":"🌩️",
    "FMCSA":"🏛️", "Jobs":"💼", "Safety":"🛡️", "Business":"📈"
  };

  const FALLBACK_NEWS = [
    { headline:"FMCSA Proposes New Sleep Apnea Screening Requirements for CDL Drivers", summary:"The Federal Motor Carrier Safety Administration is moving forward with rulemaking that would require CDL holders to undergo sleep apnea screening as part of their DOT physical. Drivers testing positive could face treatment requirements before operating a CMV.", category:"FMCSA", source:"FMCSA.dot.gov", timeAgo:"2 hours ago" },
    { headline:"Diesel Prices Drop for Third Consecutive Week - National Average Now $3.61/Gallon", summary:"The national average diesel price fell another 4 cents this week, providing some relief to owner-operators facing margin pressure. Prices are lowest in the Gulf Coast region at $3.42 and highest in California at $4.89.", category:"Fuel", source:"EIA Weekly Report", timeAgo:"5 hours ago" },
    { headline:"I-70 Mountain Corridor Restrictions: Chain Law in Effect Through Colorado Pass", summary:"CDOT has activated chain law requirements for commercial vehicles on I-70 between Vail and Georgetown. Drivers without chains or adequate traction devices face $500 fines and mandatory turnaround.", category:"Weather", source:"CDOT", timeAgo:"1 hour ago" },
    { headline:"New ELD Mandate Update: FMCSA Clarifies Personal Conveyance Rules for 2025", summary:"FMCSA released updated guidance on personal conveyance, clarifying that drivers may use PC status when traveling to obtain rest at a nearby location when no safe parking exists at current location. The update addresses a long-disputed gray area.", category:"Regulations", source:"Transport Topics", timeAgo:"3 hours ago" },
    { headline:"Trucking Companies Adding 12,000+ Jobs as Freight Volume Rebounds", summary:"Carriers across the Midwest and Southeast are actively hiring company drivers with sign-on bonuses averaging $8,000-$12,000. Refrigerated and flatbed specialists are seeing the strongest demand.", category:"Jobs", source:"FreightWaves", timeAgo:"6 hours ago" },
    { headline:"CVSA Brake Safety Week Results: 1 in 7 Trucks Placed Out of Service", summary:"The Commercial Vehicle Safety Alliance released results from its annual brake safety inspection blitz showing 14.5% of inspected vehicles had brake violations serious enough for out-of-service orders. Slack adjuster and lining issues topped the list.", category:"Safety", source:"CVSA", timeAgo:"8 hours ago" },
    { headline:"Owner-Operator Spot Rates Climb as Capacity Tightens in Key Lanes", summary:"DAT Freight & Analytics reports spot rates on major lanes have increased 12 cents per mile over the past 30 days as driver capacity tightens heading into peak season. Owner-operators on the spot market are seeing improved margins for the first time in 18 months.", category:"Business", source:"DAT Freight & Analytics", timeAgo:"4 hours ago" },
    { headline:"California AB 5 Enforcement Update: What Independent Contractors Need to Know", summary:"California continues enforcement of AB 5 worker classification rules affecting owner-operators. The Ninth Circuit ruling last month upheld the law, and carriers operating in California are advised to review their contractor agreements immediately.", category:"Regulations", source:"Land Line Magazine", timeAgo:"12 hours ago" },
    { headline:"New Hours of Service Exemption for Agricultural Transport Extended Through 2026", summary:"FMCSA has extended the agricultural commodity HOS exemption allowing drivers transporting agricultural products within 150 air miles of the source to be exempt from standard HOS rules during planting and harvest seasons.", category:"FMCSA", source:"FMCSA.dot.gov", timeAgo:"1 day ago" },
    { headline:"Winter Storm Warning: I-80 Wyoming Closures Expected This Weekend", summary:"The National Weather Service is forecasting blizzard conditions across southern Wyoming Friday through Sunday with wind gusts to 65 mph. Wyoming DOT advises commercial drivers to delay travel or plan alternate routes via I-70.", category:"Weather", source:"NWS Cheyenne", timeAgo:"30 minutes ago" },
  ];

  const fetchNews = async () => {
    setLoading(true);
    setError(null);
    try {
      const cat = activeCategory === "All" ? "" : activeCategory;
      const response = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1500,
          tools: [{ type: "web_search_20250305", name: "web_search" }],
          system: "You are a trucking industry news aggregator. Search for latest real trucking news and return ONLY a valid JSON array. No markdown, no backticks, no explanation. Each item must have: headline, summary (2 sentences), category (Regulations|Fuel|Weather|FMCSA|Jobs|Safety|Business), source, timeAgo.",
          messages: [{
            role: "user",
            content: `Search for the latest trucking news today${cat ? " about "+cat : ""}. Return 8 articles as a JSON array only.`
          }]
        })
      });
      const data = await response.json();
      const fullText = (data.content || []).map(b => b.type === "text" ? b.text : "").join("");
      const match = fullText.match(/\[[\s\S]*\]/);
      if (match) {
        const parsed = JSON.parse(match[0]);
        if (Array.isArray(parsed) && parsed.length > 0) {
          setArticles(parsed);
          setLastFetched(new Date());
          setLoading(false);
          return;
        }
      }
      throw new Error("No articles parsed");
    } catch(e) {
      // Use fallback news when API/sandbox blocks the call
      const filtered = activeCategory === "All"
        ? FALLBACK_NEWS
        : FALLBACK_NEWS.filter(a => a.category === activeCategory);
      setArticles(filtered.length > 0 ? filtered : FALLBACK_NEWS);
      setLastFetched(new Date());
    }
    setLoading(false);
  };

  const fetchDigest = async () => {
    setDigestLoading(true);
    try {
      const response = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          tools: [{ type: "web_search_20250305", name: "web_search" }],
          system: `You are Big Earl, a 30-year veteran trucker with 3.2 million miles. You speak plainly, directly, and always from experience. Write a weekly digest for truck drivers covering the top 3 things happening in trucking right now. Format as JSON: { "week": "Week of [date]", "intro": "1 sentence from Earl", "stories": [{ "title": "string", "earl_take": "Earl's 2-3 sentence honest opinion on this story - what it means for drivers on the ground" }] }. Return JSON only, no markdown.`,
          messages: [{
            role: "user",
            content: "Search for the most important trucking news this week. Write Big Earl's weekly digest covering the top 3 stories that affect CDL drivers and owner-operators. Be direct and practical - what does this mean for drivers making real decisions?"
          }]
        })
      });
      const data = await response.json();
      const fullText = data.content.map(b => b.type === "text" ? b.text : "").join("");
      const clean = fullText.replace(/```json|```/g, "").trim();
      setDigest(JSON.parse(clean));
    } catch(e) {
      // Fallback digest for sandbox/preview environment
      setDigest({
        week: "Week of " + new Date().toLocaleDateString("en-US", {month:"long", day:"numeric", year:"numeric"}),
        intro: "Thirty years behind the wheel and I still read the news every morning. Here is what matters this week.",
        stories: [
          { title:"Diesel Prices Finally Dropping - But Don't Get Comfortable", earl_take:"Three weeks down in a row on diesel is good news, but I have seen this movie before. Prices drop, carriers get comfortable, then something happens in the Middle East or a refinery goes down and we are back to $5 diesel inside of 60 days. Lock in your fuel surcharge agreements now while shippers are feeling generous." },
          { title:"FMCSA Sleep Apnea Rules Are Coming - Get Ahead of It Now", earl_take:"I know guys who fought this for years and eventually got diagnosed anyway. Sleep apnea is real and it kills drivers. If you snore, if your spouse says you stop breathing at night, go get tested on your own terms before the DOT makes you do it. A CPAP machine is not the end of your career. An accident because you fell asleep is." },
          { title:"Spot Rates Improving - Owner-Ops Starting to See Real Money Again", earl_take:"The freight recession has been brutal for independent operators. Rates are finally moving up in key lanes. My advice: do not lock into long-term contracts right now. Stay flexible on the spot market for another 60-90 days and ride this wave before committing to dedicated lanes at rates that reflect where we were six months ago." },
        ]
      });
    }
    setDigestLoading(false);
  };

  useEffect(() => { fetchNews(); }, []);
  useEffect(() => { if(activeTab === "digest" && !digest) fetchDigest(); }, [activeTab]);
  useEffect(() => { if(activeTab === "feed") fetchNews(); }, [activeCategory]);

  const filteredArticles = activeCategory === "All"
    ? articles
    : articles.filter(a => a.category === activeCategory);

  const CAT_COLORS = {
    "Regulations": C.amber, "Fuel": "#10B981", "Weather": "#60A5FA",
    "FMCSA": "#F87171", "Jobs": "#A78BFA", "Safety": "#FB923C",
    "Business": C.blue, "Industry": C.gray2,
  };

  return (
    <div style={{ background: C.bg1, minHeight:"100vh" }}>
      <PageHeader title="Trucker News" subtitle="LIVE INDUSTRY UPDATES" color={C.blue} back="Resources" onBack={() => go("resources")} />

      {/* Tab switcher */}
      <div style={{ display:"flex", borderBottom:`1px solid ${C.border}`, background:C.bg2 }}>
        {[["feed","📡 Live Feed"],["digest","🧔🏿 Earl's Digest"]].map(([id,label]) => (
          <button key={id} onClick={() => setActiveTab(id)} style={{
            flex:1, padding:"12px 0", background:"none", border:"none",
            borderBottom: activeTab===id ? `2px solid ${C.blue}` : "2px solid transparent",
            color: activeTab===id ? C.blue : C.gray2,
            fontSize:12, fontWeight:700, fontFamily:"Oswald,sans-serif",
            letterSpacing:1, cursor:"pointer",
          }}>{label}</button>
        ))}
      </div>

      {/* ── LIVE FEED TAB ── */}
      {activeTab === "feed" && (
        <div>
          {/* Category filter */}
          <div style={{ overflowX:"auto", display:"flex", gap:8, padding:"12px 16px", borderBottom:`1px solid ${C.border}` }}>
            {CATEGORIES.map(cat => (
              <button key={cat} onClick={() => setActiveCategory(cat)} style={{
                flexShrink:0, background: activeCategory===cat ? C.blue+"20" : C.bg3,
                border:`1px solid ${activeCategory===cat ? C.blue : C.border}`,
                borderRadius:20, padding:"5px 12px", cursor:"pointer",
                color: activeCategory===cat ? C.blue : C.gray2,
                fontSize:11, fontFamily:"Barlow,sans-serif", fontWeight:600,
                whiteSpace:"nowrap",
              }}>
                {CAT_ICONS[cat]} {cat}
              </button>
            ))}
          </div>

          {/* Refresh bar */}
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"8px 16px", background:C.bg2 }}>
            <div style={{ color:C.gray2, fontSize:10, fontFamily:"Barlow,sans-serif" }}>
              {lastFetched ? `Updated ${lastFetched.toLocaleTimeString([], {hour:"2-digit",minute:"2-digit"})}` : "Fetching latest..."}
            </div>
            <button onClick={fetchNews} disabled={loading} style={{
              background:"none", border:`1px solid ${C.border}`, borderRadius:20,
              padding:"4px 12px", color: loading ? C.gray2 : C.blue,
              fontSize:10, fontFamily:"Barlow,sans-serif", cursor:"pointer",
            }}>
              {loading ? "⟳ Loading..." : "⟳ Refresh"}
            </button>
          </div>

          <div style={{ padding:"12px 16px" }}>
            {loading && articles.length === 0 && (
              <div style={{ textAlign:"center", padding:"40px 20px" }}>
                <div style={{ fontSize:40, marginBottom:12 }}>📡</div>
                <div style={{ color:C.blue, fontSize:14, fontFamily:"Barlow,sans-serif", fontWeight:600 }}>
                  Scanning the wire...
                </div>
                <div style={{ color:C.gray2, fontSize:12, fontFamily:"Barlow,sans-serif", marginTop:6 }}>
                  Pulling latest trucking news
                </div>
              </div>
            )}

            {error && (
              <div style={{ background:"#EF535020", border:`1px solid #EF535040`, borderRadius:12, padding:16, marginBottom:12 }}>
                <div style={{ color:"#EF5350", fontSize:13, fontFamily:"Barlow,sans-serif" }}>{error}</div>
                <button onClick={fetchNews} style={{ marginTop:10, background:C.blue, border:"none", borderRadius:8, padding:"8px 16px", color:"#fff", fontSize:12, cursor:"pointer" }}>Try Again</button>
              </div>
            )}

            {!loading && !error && filteredArticles.length === 0 && articles.length > 0 && (
              <div style={{ textAlign:"center", padding:"30px 20px", color:C.gray2, fontSize:13, fontFamily:"Barlow,sans-serif" }}>
                No {activeCategory} news right now. Try another category.
              </div>
            )}

            {filteredArticles.map((item, i) => (
              <div key={i} style={{
                background:C.bg2, borderRadius:12, padding:16, marginBottom:12,
                border:`1px solid ${C.border}`,
                animation:`slideUp .3s ease ${i*.05}s both`,
              }}>
                {/* Category + source + time */}
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:8 }}>
                  <div style={{ display:"flex", gap:6, alignItems:"center" }}>
                    <div style={{
                      background:(CAT_COLORS[item.category]||C.gray2)+"20",
                      border:`1px solid ${(CAT_COLORS[item.category]||C.gray2)}40`,
                      borderRadius:20, padding:"2px 8px",
                      color: CAT_COLORS[item.category]||C.gray2,
                      fontSize:9, fontFamily:"Barlow,sans-serif", fontWeight:700,
                    }}>{item.category?.toUpperCase()}</div>
                    <div style={{ color:C.gray2, fontSize:10, fontFamily:"Barlow,sans-serif" }}>{item.source}</div>
                  </div>
                  <div style={{ color:C.gray2, fontSize:10, fontFamily:"Barlow,sans-serif" }}>{item.timeAgo}</div>
                </div>
                {/* Headline */}
                <div style={{ color:C.white, fontSize:14, fontWeight:600, lineHeight:1.4, marginBottom:8, fontFamily:"Barlow,sans-serif" }}>
                  {item.headline}
                </div>
                {/* Summary */}
                <div style={{ color:C.gray2, fontSize:12, fontFamily:"Barlow,sans-serif", lineHeight:1.6 }}>
                  {item.summary}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ── BIG EARL DIGEST TAB ── */}
      {activeTab === "digest" && (
        <div style={{ padding:"16px" }}>
          {digestLoading && !digest && (
            <div style={{ textAlign:"center", padding:"40px 20px" }}>
              <div style={{ fontSize:52, marginBottom:12 }}>🧔🏿</div>
              <div style={{ color:C.amber, fontSize:14, fontFamily:"Oswald,sans-serif", fontWeight:700, letterSpacing:1 }}>
                EARL IS READING THE WIRE...
              </div>
              <div style={{ color:C.gray2, fontSize:12, fontFamily:"Barlow,sans-serif", marginTop:8 }}>
                Pulling this week's top stories
              </div>
            </div>
          )}

          {digest && !digest.error && (
            <>
              {/* Earl header */}
              <div style={{ background:"linear-gradient(135deg,#1a1006,#0d0c0a)", border:`1px solid ${C.amber}30`, borderRadius:16, padding:20, marginBottom:16 }}>
                <div style={{ display:"flex", alignItems:"center", gap:14, marginBottom:12 }}>
                  <div style={{ fontSize:52 }}>🧔🏿</div>
                  <div>
                    <div style={{ color:C.amber, fontSize:16, fontFamily:"Oswald,sans-serif", fontWeight:700, letterSpacing:1 }}>
                      BIG EARL'S WEEKLY DIGEST
                    </div>
                    <div style={{ color:C.gray2, fontSize:11, fontFamily:"Barlow,sans-serif", marginTop:2 }}>
                      {digest.week}
                    </div>
                  </div>
                </div>
                <div style={{ color:"#C0B090", fontSize:13, fontFamily:"Barlow,sans-serif", fontStyle:"italic", lineHeight:1.6, borderLeft:`3px solid ${C.amber}`, paddingLeft:12 }}>
                  "{digest.intro}"
                </div>
              </div>

              {/* Stories */}
              {digest.stories?.map((story, i) => (
                <div key={i} style={{
                  background:C.bg2, border:`1px solid ${C.amber}20`, borderRadius:12,
                  marginBottom:12, overflow:"hidden",
                  animation:`slideUp .4s ease ${i*.1}s both`,
                }}>
                  <div style={{ background:C.amber+"15", padding:"10px 16px", borderBottom:`1px solid ${C.amber}20` }}>
                    <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                      <div style={{ color:C.amber, fontSize:11, fontFamily:"Oswald,sans-serif", fontWeight:700 }}>
                        STORY {i+1}
                      </div>
                      <div style={{ color:C.white, fontSize:13, fontWeight:600, fontFamily:"Barlow,sans-serif" }}>
                        {story.title}
                      </div>
                    </div>
                  </div>
                  <div style={{ padding:16 }}>
                    <div style={{ display:"flex", gap:10, alignItems:"flex-start" }}>
                      <div style={{ fontSize:28, flexShrink:0 }}>🧔🏿</div>
                      <div style={{ color:"#C0B090", fontSize:13, fontFamily:"Barlow,sans-serif", fontStyle:"italic", lineHeight:1.7 }}>
                        "{story.earl_take}"
                      </div>
                    </div>
                  </div>
                </div>
              ))}

              {/* Refresh digest */}
              <button onClick={fetchDigest} disabled={digestLoading} style={{
                width:"100%", marginTop:4, padding:14,
                background:C.amber+"20", border:`1px solid ${C.amber}40`,
                borderRadius:12, color:C.amber,
                fontSize:12, fontFamily:"Oswald,sans-serif", fontWeight:700,
                letterSpacing:1.5, cursor:"pointer",
              }}>
                {digestLoading ? "EARL IS THINKING..." : "🔄 GET FRESH TAKE FROM EARL"}
              </button>
            </>
          )}

          {digest?.error && (
            <div style={{ textAlign:"center", padding:"30px 20px" }}>
              <div style={{ fontSize:40, marginBottom:12 }}>📡</div>
              <div style={{ color:C.gray2, fontSize:13, fontFamily:"Barlow,sans-serif" }}>
                Could not reach Earl right now. Check your connection.
              </div>
              <button onClick={fetchDigest} style={{ marginTop:16, background:C.amber, border:"none", borderRadius:8, padding:"10px 20px", color:"#000", fontSize:12, fontWeight:700, cursor:"pointer" }}>
                Try Again
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function FeedbackScreen({ go, profile }) {
  const [rating, setRating]           = useState(0);
  const [hovered, setHovered]         = useState(0);
  const [category, setCategory]       = useState("");
  const [message, setMessage]         = useState("");
  const [submitted, setSubmitted]     = useState(false);
  const [submitting, setSubmitting]   = useState(false);
  const [featureVotes, setFeatureVotes] = useState({});

  const CATEGORIES = [
    { id:"bug",        icon:"🐛", label:"Bug Report",         color:"#EF5350" },
    { id:"feature",    icon:"💡", label:"Feature Request",    color:C.blue },
    { id:"content",    icon:"📚", label:"Content Feedback",   color:C.amber },
    { id:"ux",         icon:"🎨", label:"App Experience",     color:"#10B981" },
    { id:"praise",     icon:"🔥", label:"Something I Love",   color:"#F59E0B" },
    { id:"other",      icon:"💬", label:"Other",              color:C.gray2 },
  ];

  const FEATURES = [
    { id:"offline",   label:"Offline Mode",              icon:"📴" },
    { id:"audio",     label:"Audio Lessons",             icon:"🎧" },
    { id:"practice",  label:"Mock CDL Exam Timer",       icon:"⏱️" },
    { id:"logbook",   label:"Digital Trip Logbook",      icon:"📓" },
    { id:"weather",   label:"Live Route Weather Map",    icon:"🌩️" },
    { id:"salary",    label:"Pay & Salary Tracker",      icon:"💰" },
    { id:"mentor",    label:"Live Mentor Calls",         icon:"📞" },
    { id:"spanish",   label:"Spanish Language Support",  icon:"🇪🇸" },
  ];

  const RATING_LABELS = ["","Needs Work","Getting There","Pretty Good","Really Good","Outstanding"];

  const handleSubmit = async () => {
    if (!rating || !category) return;
    setSubmitting(true);
    try {
      await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 100,
          system: "You receive app feedback. Respond only with: {'received': true}",
          messages: [{
            role: "user",
            content: JSON.stringify({
              app: "StreetSmartTrucker",
              user: profile?.name || "Anonymous",
              plan: profile?.plan || "free",
              rating,
              category,
              message,
              featureVotes,
              timestamp: new Date().toISOString(),
            })
          }]
        })
      });
    } catch(e) {}
    setSubmitting(false);
    setSubmitted(true);
  };

  if (submitted) {
    return (
      <div style={{ background:C.bg1, minHeight:"100vh" }}>
        <PageHeader title="Feedback" subtitle="THANK YOU" color="#A78BFA" back="Profile" onBack={() => go("profile")} />
        <div style={{ padding:"60px 24px", textAlign:"center" }}>
          <div style={{ fontSize:72, marginBottom:20 }}>🙏</div>
          <div style={{ color:"#A78BFA", fontSize:22, fontFamily:"Oswald,sans-serif", fontWeight:700, letterSpacing:1, marginBottom:12 }}>
            THANK YOU, {(profile?.name||"DRIVER").toUpperCase()}
          </div>
          <div style={{ color:C.gray2, fontSize:14, fontFamily:"Barlow,sans-serif", lineHeight:1.7, marginBottom:32 }}>
            Your feedback goes directly to the team. Every report, every suggestion, every rating helps us build the best CDL training app on the road.
          </div>
          <div style={{ background:"#A78BFA15", border:"1px solid #A78BFA30", borderRadius:16, padding:20, marginBottom:24 }}>
            <div style={{ color:"#A78BFA", fontSize:13, fontWeight:700, fontFamily:"Barlow,sans-serif", marginBottom:8 }}>YOUR RATING</div>
            <div style={{ display:"flex", justifyContent:"center", gap:6, marginBottom:8 }}>
              {[1,2,3,4,5].map(s => (
                <span key={s} style={{ fontSize:28, color: s <= rating ? "#F59E0B" : C.gray2 }}>★</span>
              ))}
            </div>
            <div style={{ color:C.amber, fontSize:13, fontFamily:"Barlow,sans-serif" }}>{RATING_LABELS[rating]}</div>
          </div>
          <button onClick={() => go("profile")} style={{
            background:"#A78BFA", border:"none", borderRadius:12,
            padding:"14px 32px", color:"#fff", fontSize:13,
            fontWeight:700, fontFamily:"Oswald,sans-serif",
            letterSpacing:1.5, cursor:"pointer",
          }}>BACK TO PROFILE</button>
        </div>
      </div>
    );
  }

  return (
    <div style={{ background:C.bg1, minHeight:"100vh", paddingBottom:40 }}>
      <PageHeader title="Feedback" subtitle="RATE & REVIEW" color="#A78BFA" back="Profile" onBack={() => go("profile")} />

      <div style={{ padding:"20px 20px 0" }}>

        {/* Star Rating */}
        <div style={{ background:C.bg2, border:"1px solid #A78BFA30", borderRadius:16, padding:20, marginBottom:16, textAlign:"center" }}>
          <div style={{ color:"#A78BFA", fontSize:9, letterSpacing:2, fontFamily:"Barlow,sans-serif", fontWeight:700, marginBottom:14 }}>
            HOW WOULD YOU RATE STREETSMART?
          </div>
          <div style={{ display:"flex", justifyContent:"center", gap:8, marginBottom:10 }}>
            {[1,2,3,4,5].map(s => (
              <button key={s}
                onClick={() => setRating(s)}
                onMouseEnter={() => setHovered(s)}
                onMouseLeave={() => setHovered(0)}
                style={{ background:"none", border:"none", cursor:"pointer", padding:4, fontSize:40,
                  color: s <= (hovered||rating) ? "#F59E0B" : "#333",
                  transform: s <= (hovered||rating) ? "scale(1.15)" : "scale(1)",
                  transition:"all .15s ease",
                }}>★</button>
            ))}
          </div>
          {rating > 0 && (
            <div style={{ color:C.amber, fontSize:13, fontFamily:"Barlow,sans-serif", fontWeight:600 }}>
              {RATING_LABELS[rating]}
            </div>
          )}
        </div>

        {/* Category */}
        <div style={{ marginBottom:16 }}>
          <div style={{ color:C.gray2, fontSize:9, letterSpacing:2, fontFamily:"Barlow,sans-serif", fontWeight:700, marginBottom:10 }}>
            WHAT ARE YOU SHARING?
          </div>
          <div style={{ display:"flex", flexWrap:"wrap", gap:8 }}>
            {CATEGORIES.map(cat => (
              <button key={cat.id} onClick={() => setCategory(cat.id)} style={{
                background: category===cat.id ? cat.color+"25" : C.bg2,
                border:`1px solid ${category===cat.id ? cat.color : C.border}`,
                borderRadius:20, padding:"8px 14px", cursor:"pointer",
                display:"flex", alignItems:"center", gap:6,
                color: category===cat.id ? cat.color : C.gray2,
                fontSize:12, fontFamily:"Barlow,sans-serif", fontWeight:600,
              }}>
                <span>{cat.icon}</span> {cat.label}
              </button>
            ))}
          </div>
        </div>

        {/* Message */}
        <div style={{ marginBottom:16 }}>
          <div style={{ color:C.gray2, fontSize:9, letterSpacing:2, fontFamily:"Barlow,sans-serif", fontWeight:700, marginBottom:10 }}>
            TELL US MORE {category === "bug" ? "(WHAT HAPPENED?)" : category === "feature" ? "(WHAT WOULD YOU BUILD?)" : ""}
          </div>
          <textarea
            value={message}
            onChange={e => setMessage(e.target.value)}
            placeholder={
              category === "bug" ? "Describe what happened, which screen it was on, and what you expected..." :
              category === "feature" ? "What would make StreetSmart even better for you?" :
              category === "praise" ? "What do you love about the app?" :
              "Share your thoughts with the team..."
            }
            style={{
              width:"100%", minHeight:100, background:C.bg2,
              border:`1px solid ${C.border}`, borderRadius:12,
              padding:14, color:C.white, fontSize:13,
              fontFamily:"Barlow,sans-serif", lineHeight:1.6,
              resize:"none", outline:"none",
              boxSizing:"border-box",
            }}
          />
          <div style={{ color:C.gray2, fontSize:10, fontFamily:"Barlow,sans-serif", marginTop:4, textAlign:"right" }}>
            {message.length}/500
          </div>
        </div>

        {/* Feature vote */}
        <div style={{ marginBottom:20 }}>
          <div style={{ color:C.gray2, fontSize:9, letterSpacing:2, fontFamily:"Barlow,sans-serif", fontWeight:700, marginBottom:10 }}>
            VOTE FOR FEATURES YOU WANT NEXT
          </div>
          <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
            {FEATURES.map(f => {
              const voted = featureVotes[f.id];
              return (
                <button key={f.id} onClick={() => setFeatureVotes(v => ({...v, [f.id]: !v[f.id]}))}
                  style={{
                    background: voted ? "#A78BFA15" : C.bg2,
                    border:`1px solid ${voted ? "#A78BFA50" : C.border}`,
                    borderRadius:10, padding:"11px 14px", cursor:"pointer",
                    display:"flex", alignItems:"center", gap:10, textAlign:"left",
                  }}>
                  <span style={{ fontSize:18 }}>{f.icon}</span>
                  <span style={{ color: voted ? "#A78BFA" : C.offWhite, fontSize:13, fontFamily:"Barlow,sans-serif", flex:1 }}>{f.label}</span>
                  <div style={{
                    width:22, height:22, borderRadius:6,
                    background: voted ? "#A78BFA" : "transparent",
                    border:`2px solid ${voted ? "#A78BFA" : C.gray2}`,
                    display:"flex", alignItems:"center", justifyContent:"center",
                    flexShrink:0,
                  }}>
                    {voted && <span style={{ color:"#fff", fontSize:13, fontWeight:700 }}>✓</span>}
                  </div>
                </button>
              );
            })}
          </div>
        </div>

        {/* Submit */}
        <button
          onClick={handleSubmit}
          disabled={!rating || !category || submitting}
          style={{
            width:"100%", padding:16,
            background: (!rating || !category) ? C.bg3 : "linear-gradient(135deg,#A78BFA,#7C3AED)",
            border:"none", borderRadius:14,
            color: (!rating || !category) ? C.gray2 : "#fff",
            fontSize:14, fontWeight:700,
            fontFamily:"Oswald,sans-serif", letterSpacing:2,
            cursor: (!rating || !category) ? "not-allowed" : "pointer",
            transition:"all .2s ease",
          }}>
          {submitting ? "SENDING..." : "SUBMIT FEEDBACK"}
        </button>
        {(!rating || !category) && (
          <div style={{ color:C.gray2, fontSize:11, fontFamily:"Barlow,sans-serif", textAlign:"center", marginTop:8 }}>
            Select a star rating and category to submit
          </div>
        )}
      </div>
    </div>
  );
}


// ─── PROFILE ──────────────────────────────────────────────────────────────────
function ProfileScreen({ go, profile, setProfile, progress, track, setTrack }) {
  const [editName, setEditName] = useState(false);
  const [nameVal, setNameVal]   = useState(profile.name);
  const currentPlan = PLANS.find(p=>p.id===profile.plan) || PLANS[0];
  const activeTrack = track || TRACKS[0];
  return (
    <div>
      <PageHeader title="Profile" subtitle="YOUR ACCOUNT AND SUBSCRIPTION" color={C.amber} />
      <div style={{ padding:"18px 24px" }}>
        {/* User card */}
        <Card style={{ marginBottom:18, padding:20 }}>
          <div style={{ display:"flex", gap:14, alignItems:"center", marginBottom:14 }}>
            <div style={{ width:56, height:56, borderRadius:"50%", background:C.bg3, border:`2px solid ${C.amber}`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:28 }}>🧑‍✈️</div>
            <div style={{ flex:1 }}>
              {editName ? (
                <input value={nameVal} onChange={e=>setNameVal(e.target.value)} onBlur={()=>{setProfile(p=>({...p,name:nameVal}));setEditName(false);}} autoFocus
                  style={{ background:C.bg3, border:`1px solid ${C.amber}`, borderRadius:8, padding:"6px 10px", color:C.white, fontSize:18, fontFamily:"Oswald,sans-serif", width:"100%", outline:"none", marginBottom:6 }} />
              ) : (
                <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:4 }}>
                  <div style={{ color:C.white, fontSize:18, fontWeight:700 }}>{profile.name}</div>
                  <button onClick={()=>setEditName(true)} style={{ background:"none", border:"none", color:C.amber, fontSize:11, cursor:"pointer", fontFamily:"Barlow,sans-serif" }}>edit</button>
                </div>
              )}
              <div style={{ color:C.gray2, fontSize:12, fontFamily:"Barlow,sans-serif" }}>Path: {activeTrack.label}</div>
              <div style={{ display:"flex", alignItems:"center", gap:6, marginTop:4 }}>
                <span style={{ color:C.gray2, fontSize:12, fontFamily:"Barlow,sans-serif" }}>Plan:</span>
                <span style={{ color:currentPlan.color, fontSize:13, fontWeight:700 }}>{currentPlan.name.toUpperCase()}</span>
              </div>
            </div>
          </div>
          {/* Quick stats */}
          <div style={{ display:"flex", borderTop:`1px solid ${C.border}`, paddingTop:14 }}>
            {[["📚",progress.completed.length,"LESSONS"],["🎮",Object.keys(progress.simScores).length,"SIMS"],["⭐",progress.xp,"XP"]].map(([icon,val,label],i)=>(
              <div key={i} style={{ flex:1, textAlign:"center", borderRight:i<2?`1px solid ${C.border}`:"none" }}>
                <div style={{ fontSize:18 }}>{icon}</div>
                <div style={{ color:C.amber, fontSize:18, fontWeight:700 }}>{val}</div>
                <div style={{ color:C.gray2, fontSize:9, letterSpacing:1.5, fontFamily:"Barlow,sans-serif" }}>{label}</div>
              </div>
            ))}
          </div>
        </Card>

        {/* Change path */}
        <div style={{ color:C.gray2, fontSize:10, letterSpacing:3, fontFamily:"Barlow,sans-serif", marginBottom:10 }}>CHANGE YOUR PATH</div>
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:8, marginBottom:22 }}>
          {TRACKS.map(t => (
            <button key={t.id} onClick={() => setTrack(t)}
              style={{ background:activeTrack.id===t.id?`${t.color}20`:C.bg2, border:`1px solid ${activeTrack.id===t.id?t.color:C.border}`, borderRadius:12, padding:"12px 8px", cursor:"pointer", display:"flex", flexDirection:"column", alignItems:"center", gap:6 }}>
              <div style={{ fontSize:22 }}>{t.icon}</div>
              <div style={{ color:activeTrack.id===t.id?t.color:C.gray2, fontSize:11, fontFamily:"Barlow,sans-serif", fontWeight:600 }}>{t.short}</div>
            </button>
          ))}
        </div>

        {/* Plans */}
        <div style={{ color:C.gray2, fontSize:10, letterSpacing:3, fontFamily:"Barlow,sans-serif", marginBottom:12 }}>SUBSCRIPTION PLANS</div>
        {PLANS.map(plan => {
          const active = profile.plan===plan.id;
          return (
            <div key={plan.id} style={{ background:active?`${plan.color}08`:C.bg2, border:`1px solid ${active?`${plan.color}40`:C.border}`, borderRadius:16, padding:18, marginBottom:12, position:"relative" }}>
              {plan.badge && (
                <div style={{ marginBottom:8 }}>
                  <Tag label={plan.badge} color={plan.color} small />
                </div>
              )}
              <div style={{ display:"flex", alignItems:"baseline", gap:8, marginBottom:12 }}>
                <div style={{ color:active?plan.color:C.white, fontSize:18, fontWeight:700 }}>{plan.name.toUpperCase()}</div>
                {active && <Tag label="ACTIVE" color={plan.color} small />}
                <div style={{ marginLeft:"auto", color:active?plan.color:C.gray1, fontSize:16, fontWeight:700 }}>{plan.price}<span style={{ fontSize:11, color:C.gray2 }}>{plan.period}</span></div>
              </div>
              {plan.features.map((f,i) => (
                <div key={i} style={{ display:"flex", gap:8, marginBottom:6 }}>
                  <div style={{ color:plan.color, fontSize:12, flexShrink:0 }}>✓</div>
                  <div style={{ color:C.offWhite, fontSize:12, fontFamily:"Barlow,sans-serif" }}>{f}</div>
                </div>
              ))}
              {!active && (
                <button onClick={()=>setProfile(p=>({...p,plan:plan.id}))} style={{ width:"100%", marginTop:12, padding:"10px", background:`${plan.color}20`, border:`1px solid ${plan.color}40`, borderRadius:10, color:plan.color, fontSize:12, fontWeight:600, letterSpacing:1, cursor:"pointer", fontFamily:"Barlow,sans-serif" }}>
                  SELECT PLAN
                </button>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}


// ─── BOOKMARKS SCREEN ─────────────────────────────────────────────────────────
function BookmarksScreen({ go, progress, setProgress }) {
  const bookmarked = progress.bookmarked || [];
  const [current, setCurrent] = useState(0);
  const [answers, setAnswers] = useState({});
  const [mode, setMode] = useState("list"); // list | drill

  if(mode === "drill" && bookmarked.length > 0) {
    const q = bookmarked[current];
    const picked = answers[current];
    return (
      <div>
        <PageHeader title="Bookmark Drill" subtitle="SAVED QUESTIONS" color={C.amber} back="CDL Prep" onBack={()=>go("cdl")}>
          <div style={{ color:C.gray2, fontSize:12, fontFamily:"Barlow,sans-serif", marginTop:6 }}>{current+1} of {bookmarked.length}</div>
          <div style={{ marginTop:6 }}><PBar value={((current+1)/bookmarked.length)*100} color={C.amber} height={4}/></div>
        </PageHeader>
        <div style={{ padding:"18px 24px" }}>
          <Card style={{ marginBottom:14 }}>
            <div style={{ color:C.white, fontSize:14, fontFamily:"Barlow,sans-serif", fontWeight:500, lineHeight:1.65, marginBottom:16 }}>{q.q}</div>
            {q.opts.map((opt,j)=>{
              const chosen=picked===j; const correct=q.ans===j;
              let bg=C.bg3,border=C.border2,tc=C.offWhite;
              if(picked!==undefined&&correct){bg=C.green+"15";border=C.green;tc=C.green;}
              else if(picked!==undefined&&chosen&&!correct){bg=C.red+"15";border=C.red;tc=C.red;}
              else if(chosen){bg=C.amber+"15";border=C.amber;tc=C.amber;}
              return(
                <button key={j} onClick={()=>setAnswers(a=>({...a,[current]:j}))} style={{ background:bg,border:"1px solid "+border,borderRadius:10,padding:"11px 14px",cursor:"pointer",display:"flex",alignItems:"center",gap:10,textAlign:"left",marginBottom:8,width:"100%" }}>
                  <div style={{ width:27,height:27,borderRadius:"50%",background:chosen?(picked!==undefined?(correct?C.green:C.red):C.amber):C.bg2,display:"flex",alignItems:"center",justifyContent:"center",color:chosen?"#000":C.gray2,fontSize:11,fontWeight:700,flexShrink:0 }}>{["A","B","C","D"][j]}</div>
                  <div style={{ color:tc,fontSize:13,fontFamily:"Barlow,sans-serif" }}>{opt}</div>
                </button>
              );
            })}
            {picked!==undefined&&(
              <div style={{ marginTop:10,background:picked===q.ans?C.green+"10":C.red+"10",borderRadius:10,padding:"11px 14px" }}>
                <div style={{ color:picked===q.ans?C.green:C.red,fontSize:10,fontFamily:"Barlow,sans-serif",fontWeight:700,letterSpacing:1.5,marginBottom:4 }}>{picked===q.ans?"CORRECT":"INCORRECT"}</div>
                <div style={{ color:C.offWhite,fontSize:12,fontFamily:"Barlow,sans-serif",lineHeight:1.6 }}>{q.exp}</div>
              </div>
            )}
          </Card>
          {picked!==undefined && (
            <div style={{ display:"flex",gap:10 }}>
              {current>0&&<button onClick={()=>setCurrent(c=>c-1)} style={{ flex:1,padding:13,background:"transparent",border:"1px solid "+C.border,borderRadius:12,color:C.gray1,fontSize:12,cursor:"pointer",fontFamily:"Oswald,sans-serif" }}>PREV</button>}
              {current<bookmarked.length-1?<button onClick={()=>{setCurrent(c=>c+1);}} style={{ flex:2,padding:13,background:"linear-gradient(135deg,"+C.amber+",#FF6B00)",border:"none",borderRadius:12,color:"#000",fontSize:13,fontWeight:700,letterSpacing:2,cursor:"pointer" }}>NEXT</button>
              :<button onClick={()=>{setMode("list");setCurrent(0);setAnswers({});}} style={{ flex:2,padding:13,background:"linear-gradient(135deg,"+C.green+","+C.green+"bb)",border:"none",borderRadius:12,color:"#000",fontSize:13,fontWeight:700,letterSpacing:2,cursor:"pointer" }}>DONE</button>}
            </div>
          )}
          <button onClick={()=>{
            setProgress(p=>({...p,bookmarked:(p.bookmarked||[]).filter(bq=>bq.q!==q.q)}));
          }} style={{ width:"100%",marginTop:12,padding:12,background:"transparent",border:"1px solid "+C.red+"40",borderRadius:12,color:C.red,fontSize:12,cursor:"pointer",fontFamily:"Barlow,sans-serif" }}>
            Remove Bookmark
          </button>
        </div>
      </div>
    );
  }

  return (
    <div>
      <PageHeader title="Saved Questions" subtitle="YOUR BOOKMARKS" color={C.amber} back="CDL Prep" onBack={()=>go("cdl")} />
      <div style={{ padding:"18px 24px" }}>
        {bookmarked.length === 0 ? (
          <div style={{ textAlign:"center", padding:"48px 24px" }}>
            <div style={{ fontSize:48, marginBottom:16 }}>🔖</div>
            <div style={{ color:C.white, fontSize:16, fontWeight:600, marginBottom:8 }}>No bookmarks yet</div>
            <div style={{ color:C.gray2, fontSize:13, fontFamily:"Barlow,sans-serif" }}>Tap the bookmark icon on any CDL question to save it here for review.</div>
          </div>
        ) : (
          <>
            <button onClick={()=>setMode("drill")} style={{ width:"100%",padding:14,background:"linear-gradient(135deg,"+C.amber+",#FF6B00)",border:"none",borderRadius:14,color:"#000",fontSize:14,fontWeight:700,letterSpacing:2,cursor:"pointer",marginBottom:16 }}>
              DRILL ALL {bookmarked.length} SAVED QUESTIONS
            </button>
            {bookmarked.map((q,i)=>(
              <Card key={i} style={{ marginBottom:8, padding:14 }}>
                <div style={{ display:"flex", justifyContent:"space-between", gap:10 }}>
                  <div style={{ color:C.offWhite, fontSize:13, fontFamily:"Barlow,sans-serif", lineHeight:1.5, flex:1 }}>{q.q}</div>
                  <button onClick={()=>setProgress(p=>({...p,bookmarked:(p.bookmarked||[]).filter(bq=>bq.q!==q.q)}))} style={{ background:"none",border:"none",color:C.red,cursor:"pointer",fontSize:16,flexShrink:0 }}>✕</button>
                </div>
                <div style={{ color:C.green, fontSize:11, fontFamily:"Barlow,sans-serif", marginTop:8 }}>Answer: {q.opts&&q.opts[q.ans]}</div>
              </Card>
            ))}
          </>
        )}
      </div>
    </div>
  );
}

// ─── COMMUNITY SCREEN ─────────────────────────────────────────────────────────
function CommunityScreen({ go, profile, progress, setProgress }) {
  const [posts, setPosts] = useState(SEED_POSTS);
  const [newQ, setNewQ] = useState("");
  const [posting, setPosting] = useState(false);
  const [aiLoading, setAiLoading] = useState(null);

  const submitPost = async () => {
    if(!newQ.trim()) return;
    const post = { id:"p"+Date.now(), author:profile.name||"Driver", avatar:"🧑‍✈️", role:"Community", time:"Just now", q:newQ, a:"", likes:0, tag:"General" };
    setPosts(p=>[post,...p]);
    const q = newQ;
    setNewQ("");
    setPosting(false);
    // Get Big Earl to answer
    setAiLoading(post.id);
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,messages:[{role:"user",content:"You are Big Earl, a 30-year veteran truck driver and mentor. Answer this question from a fellow driver in 2-4 sentences. Be direct, practical, and real. Question: "+q}]})});
      const d = await res.json();
      const answer = (d.content||[]).map(b=>b.text||"").join("") || "Great question. Post this in the app feedback and I will get back to you.";
      setPosts(p=>p.map(post=>post.q===q?{...post,a:answer}:post));
    } catch(e) {}
    setAiLoading(null);
  };

  return (
    <div>
      <PageHeader title="Community" subtitle="DRIVER TO DRIVER" color={C.blue}>
        <div style={{ color:C.gray2, fontSize:12, fontFamily:"Barlow,sans-serif", marginTop:6 }}>Ask Big Earl anything. Connect with other drivers.</div>
      </PageHeader>
      <div style={{ padding:"18px 24px" }}>
        {/* Post a question */}
        {!posting ? (
          <button onClick={()=>setPosting(true)} style={{ width:"100%",background:C.bg2,border:"1px solid "+C.border,borderRadius:14,padding:"14px 18px",cursor:"pointer",textAlign:"left",color:C.gray2,fontSize:13,fontFamily:"Barlow,sans-serif",marginBottom:16 }}>
            Ask a question - Big Earl answers... 🧔🏿
          </button>
        ) : (
          <div style={{ background:C.bg2, border:"1px solid "+C.blue+"40", borderRadius:14, padding:16, marginBottom:16 }}>
            <textarea value={newQ} onChange={e=>setNewQ(e.target.value)} placeholder="What do you want to know? CDL tips, business advice, road questions..." style={{ width:"100%",background:"transparent",border:"none",color:C.white,fontSize:13,fontFamily:"Barlow,sans-serif",lineHeight:1.6,resize:"none",outline:"none",minHeight:80 }}/>
            <div style={{ display:"flex",gap:8,marginTop:10 }}>
              <button onClick={()=>setPosting(false)} style={{ flex:1,padding:10,background:"transparent",border:"1px solid "+C.border,borderRadius:10,color:C.gray2,fontSize:12,cursor:"pointer",fontFamily:"Barlow,sans-serif" }}>Cancel</button>
              <button onClick={submitPost} style={{ flex:2,padding:10,background:"linear-gradient(135deg,"+C.blue+","+C.blue+"bb)",border:"none",borderRadius:10,color:"#000",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"Oswald,sans-serif",letterSpacing:1 }}>ASK BIG EARL</button>
            </div>
          </div>
        )}
        {/* Posts feed */}
        {posts.map((post,i)=>(
          <Card key={post.id} style={{ marginBottom:12 }}>
            <div style={{ display:"flex",gap:10,marginBottom:10 }}>
              <div style={{ width:36,height:36,borderRadius:"50%",background:C.bg3,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,flexShrink:0 }}>{post.avatar}</div>
              <div>
                <div style={{ color:C.white,fontSize:13,fontWeight:600 }}>{post.author}</div>
                <div style={{ color:C.gray2,fontSize:10,fontFamily:"Barlow,sans-serif" }}>{post.role} · {post.time}</div>
              </div>
              <div style={{ marginLeft:"auto" }}><Tag label={post.tag} color={C.blue} small/></div>
            </div>
            <div style={{ color:C.offWhite,fontSize:13,fontFamily:"Barlow,sans-serif",lineHeight:1.6,marginBottom:post.a?12:0 }}>{post.q}</div>
            {aiLoading===post.id&&(
              <div style={{ display:"flex",alignItems:"center",gap:8,padding:"10px 0" }}>
                <span style={{ fontSize:18 }}>🧔🏿</span>
                <div style={{ display:"flex",gap:4 }}>{[0,1,2].map(j=><div key={j} style={{ width:6,height:6,borderRadius:"50%",background:C.amber,animation:"pulse 1.2s ease "+j*.2+"s infinite" }}/>)}</div>
              </div>
            )}
            {post.a&&(
              <div style={{ background:"linear-gradient(135deg,#1A1200,#0D1117)",border:"1px solid "+C.amberDim,borderRadius:10,padding:12 }}>
                <div style={{ display:"flex",gap:8,marginBottom:6 }}>
                  <span style={{ fontSize:16 }}>🧔🏿</span>
                  <span style={{ color:C.amber,fontSize:10,fontFamily:"Barlow,sans-serif",fontWeight:700,letterSpacing:1.5 }}>BIG EARL SAYS</span>
                </div>
                <div style={{ color:"#ddd",fontSize:12,fontFamily:"Barlow,sans-serif",fontStyle:"italic",lineHeight:1.65 }}>{post.a}</div>
              </div>
            )}
            <div style={{ display:"flex",alignItems:"center",gap:12,marginTop:10 }}>
              <button onClick={()=>setPosts(p=>p.map(pp=>pp.id===post.id?{...pp,likes:(pp.likes||0)+1}:pp))} style={{ background:"none",border:"none",color:C.gray2,fontSize:12,cursor:"pointer",fontFamily:"Barlow,sans-serif",display:"flex",alignItems:"center",gap:4 }}>
                👍 {post.likes||0}
              </button>
            </div>
          </Card>
        ))}
      </div>
    </div>
  );
}

