// ─── INPUT ROW (defined outside to prevent focus loss on re-render) ────────────
function InputRow({ label, value, onChange, prefix, suffix }) {
  return (
    <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"12px 0", borderBottom:"1px solid "+C.border }}>
      <div style={{ color:C.gray1, fontSize:13, fontFamily:"Barlow,sans-serif" }}>{label}</div>
      <div style={{ display:"flex", alignItems:"center", gap:4 }}>
        {prefix && <span style={{ color:C.gray2, fontSize:13 }}>{prefix}</span>}
        <input
          value={value}
          onChange={e => onChange(e.target.value)}
          inputMode="decimal"
          type="text"
          style={{
            background:"transparent", border:"none",
            color:C.white, fontSize:15, fontWeight:700,
            fontFamily:"Oswald,sans-serif",
            width:80, textAlign:"right", outline:"none",
          }}
        />
        {suffix && <span style={{ color:C.gray2, fontSize:13 }}>{suffix}</span>}
      </div>
    </div>
  );
}

// ─── RATE CALCULATOR SCREEN ───────────────────────────────────────────────────
function RateCalculatorScreen({ go }) {
  const [miles, setMiles] = useState("");
  const [rate, setRate] = useState("");
  const [mpg, setMpg] = useState("6.5");
  const [fuelPrice, setFuelPrice] = useState("3.60");
  const [insurance, setInsurance] = useState("0.15");
  const [maintenance, setMaintenance] = useState("0.15");
  const [truckPayment, setTruckPayment] = useState("0.20");
  const [result, setResult] = useState(null);

  const calculate = () => {
    const m = parseFloat(miles)||0;
    const r = parseFloat(rate)||0;
    const mpgN = parseFloat(mpg)||6.5;
    const fp = parseFloat(fuelPrice)||3.60;
    const ins = parseFloat(insurance)||0;
    const maint = parseFloat(maintenance)||0;
    const truck = parseFloat(truckPayment)||0;
    const fuelCPM = fp / mpgN;
    const totalCPM = fuelCPM + ins + maint + truck;
    const gross = m * r;
    const fuelCost = m * fuelCPM;
    const totalCost = m * totalCPM;
    const net = gross - totalCost;
    const margin = gross > 0 ? (net/gross*100) : 0;
    const verdict = net > 0 ? (margin >= 25 ? "strong" : margin >= 10 ? "marginal" : "thin") : "loss";
    setResult({ gross, fuelCost, totalCost, net, margin, verdict, totalCPM, fuelCPM, m, r });
  };

  const verdictColor = result ? (result.verdict==="strong"?C.green:result.verdict==="marginal"?C.amber:C.red) : C.amber;
  const verdictLabel = result ? (result.verdict==="strong"?"TAKE IT - STRONG LOAD":result.verdict==="marginal"?"CONSIDER IT - THIN MARGIN":result.verdict==="thin"?"COUNTER FIRST - VERY THIN":"PASS - LOSING MONEY") : "";
  const verdictIcon = result ? (result.verdict==="strong"?"✅":result.verdict==="marginal"?"⚠️":"❌") : "";

  // InputRow defined outside component for stable reference

  return (
    <div>
      <PageHeader title="Rate Calculator" subtitle="LOAD PROFITABILITY" color={C.green} back="Tools" onBack={()=>go("tools")}>
        <div style={{ color:C.gray2,fontSize:12,fontFamily:"Barlow,sans-serif",marginTop:6 }}>Know your numbers before you say yes.</div>
      </PageHeader>
      <div style={{ padding:"18px 24px" }}>
        <Card style={{ marginBottom:14 }}>
          <div style={{ color:C.green,fontSize:10,letterSpacing:2,fontFamily:"Barlow,sans-serif",fontWeight:600,marginBottom:4 }}>LOAD DETAILS</div>
          <InputRow label="Total Miles" value={miles} onChange={setMiles} suffix="mi"/>
          <InputRow label="Rate Per Mile" value={rate} onChange={setRate} prefix="$" suffix="/mi"/>
        </Card>
        <Card style={{ marginBottom:14 }}>
          <div style={{ color:C.amber,fontSize:10,letterSpacing:2,fontFamily:"Barlow,sans-serif",fontWeight:600,marginBottom:4 }}>YOUR COSTS (per mile)</div>
          <InputRow label="Fuel Price" value={fuelPrice} onChange={setFuelPrice} prefix="$" suffix="/gal"/>
          <InputRow label="MPG Average" value={mpg} onChange={setMpg} suffix="mpg"/>
          <InputRow label="Insurance" value={insurance} onChange={setInsurance} prefix="$" suffix="/mi"/>
          <InputRow label="Maintenance" value={maintenance} onChange={setMaintenance} prefix="$" suffix="/mi"/>
          <InputRow label="Truck Payment" value={truckPayment} onChange={setTruckPayment} prefix="$" suffix="/mi"/>
        </Card>
        <div style={{ display:"flex", gap:10, marginBottom:16 }}>
          <button onClick={calculate} style={{ flex:2,padding:15,background:"linear-gradient(135deg,"+C.green+","+C.green+"bb)",border:"none",borderRadius:14,color:"#000",fontSize:15,fontWeight:700,letterSpacing:2,cursor:"pointer",fontFamily:"Oswald,sans-serif" }}>
            {result ? "RECALCULATE" : "CALCULATE PROFIT"}
          </button>
          {result && (
            <button onClick={()=>{
              setMiles(""); setRate(""); setMpg("6.5");
              setFuelPrice("3.60"); setInsurance("0.15");
              setMaintenance("0.15"); setTruckPayment("0.20");
              setResult(null);
            }} style={{ flex:1,padding:15,background:"transparent",border:"1px solid "+C.border,borderRadius:14,color:C.gray1,fontSize:13,letterSpacing:1,cursor:"pointer",fontFamily:"Oswald,sans-serif" }}>
              RESET
            </button>
          )}
        </div>
        {result && (
          <div style={{ animation:"slideUp .3s ease" }}>
            <div style={{ background:verdictColor+"12",border:"1px solid "+verdictColor+"40",borderRadius:14,padding:20,marginBottom:14,textAlign:"center" }}>
              <div style={{ fontSize:36,marginBottom:8 }}>{verdictIcon}</div>
              <div style={{ color:verdictColor,fontSize:16,fontWeight:700,marginBottom:4 }}>{verdictLabel}</div>
              <div style={{ color:C.gray2,fontSize:12,fontFamily:"Barlow,sans-serif" }}>Net margin: {result.margin.toFixed(1)}%</div>
            </div>
            <Card style={{ marginBottom:8 }}>
              {[
                ["Gross Revenue","$"+result.gross.toFixed(2),C.green],
                ["Fuel Cost","-$"+result.fuelCost.toFixed(2),C.red],
                ["All-In Cost","-$"+result.totalCost.toFixed(2),C.red],
                ["Your Cost Per Mile","$"+result.totalCPM.toFixed(3)+"/mi",C.amber],
                ["NET PROFIT","$"+result.net.toFixed(2),result.net>0?C.green:C.red],
              ].map(([l,v,c],i)=>(
                <div key={i} style={{ display:"flex",justifyContent:"space-between",padding:"10px 0",borderBottom:i<4?"1px solid "+C.border:"none" }}>
                  <div style={{ color:C.gray1,fontSize:13,fontFamily:"Barlow,sans-serif" }}>{l}</div>
                  <div style={{ color:c,fontSize:14,fontWeight:700 }}>{v}</div>
                </div>
              ))}
            </Card>
            {/* Big Earl counter suggestion - shows for ALL results */}
            {(() => {
              const currentRate = parseFloat(rate)||0;
              const breakEven = result.totalCPM;
              // Target: breakeven + 25% margin
              const targetRate = breakEven * 1.30;
              // Strong counter: breakeven + 40% margin
              const strongRate = breakEven * 1.45;
              const counterRate = currentRate < targetRate ? targetRate : currentRate * 1.08;
              const addedRevenue = (counterRate - currentRate) * result.m;
              const verdict = result.verdict;
              let earlText = "";
              let earlColor = C.amber;
              if(verdict === "strong") {
                earlText = "Solid load. You are making $"+result.net.toFixed(0)+" on this run at a "+result.margin.toFixed(0)+"% margin. If this broker keeps offering lanes like this, build that relationship. On future loads from them try countering at $"+counterRate.toFixed(2)+"/mi - a good broker will meet you there.";
                earlColor = C.green;
              } else if(verdict === "marginal") {
                earlText = "This works but the margin is thin. Always counter first - ask for $"+counterRate.toFixed(2)+"/mi. That is $"+addedRevenue.toFixed(0)+" more in your pocket and most brokers have room. If they say no, you still have a profitable load. If they say yes, you just made $"+addedRevenue.toFixed(0)+" for one phone call.";
                earlColor = C.amber;
              } else if(verdict === "thin") {
                earlText = "Too thin to accept as offered. Your break-even is $"+breakEven.toFixed(2)+"/mi. Counter at $"+counterRate.toFixed(2)+"/mi minimum - that gets you to a 30% margin. Tell the broker your cost per mile is $"+breakEven.toFixed(2)+" and you need $"+counterRate.toFixed(2)+" to make the run viable. A serious broker will negotiate.";
                earlColor = C.amber;
              } else {
                earlText = "Do NOT take this load as offered. At $"+currentRate.toFixed(2)+"/mi you lose $"+Math.abs(result.net).toFixed(0)+" on this run. Your break-even is $"+breakEven.toFixed(2)+"/mi. Counter at $"+strongRate.toFixed(2)+"/mi or walk away. Hauling at a loss does not keep the lights on - there is always another load.";
                earlColor = C.red;
              }
              return (
                <div style={{ background:"linear-gradient(135deg,#1A1200,#0D1117)", border:"1px solid "+earlColor+"35", borderRadius:14, padding:16, marginTop:4 }}>
                  <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:10 }}>
                    <span style={{ fontSize:22 }}>🧔🏿</span>
                    <span style={{ color:earlColor, fontSize:10, fontFamily:"Barlow,sans-serif", fontWeight:700, letterSpacing:2 }}>BIG EARL SAYS</span>
                  </div>
                  <div style={{ color:"#ddd", fontSize:13, fontFamily:"Barlow,sans-serif", fontStyle:"italic", lineHeight:1.7, marginBottom:14 }}>
                    {earlText}
                  </div>
                  {/* Counter offer box */}
                  <div style={{ background:earlColor+"15", border:"1px solid "+earlColor+"40", borderRadius:10, padding:"12px 14px", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                    <div>
                      <div style={{ color:earlColor, fontSize:10, fontFamily:"Barlow,sans-serif", fontWeight:700, letterSpacing:2, marginBottom:2 }}>SUGGESTED COUNTER</div>
                      <div style={{ color:C.gray2, fontSize:11, fontFamily:"Barlow,sans-serif" }}>30%+ margin target</div>
                    </div>
                    <div style={{ textAlign:"right" }}>
                      <div style={{ color:earlColor, fontSize:26, fontWeight:700 }}>${counterRate.toFixed(2)}<span style={{ fontSize:13 }}>/mi</span></div>
                      <div style={{ color:C.gray2, fontSize:11, fontFamily:"Barlow,sans-serif" }}>+${addedRevenue.toFixed(0)} vs offered rate</div>
                    </div>
                  </div>
                </div>
              );
            })()}
          </div>
        )}
      </div>
    </div>
  );
}


